def get_missing_profile_fields(user_id):
    """Return list of (field_name, label) for required fields that are empty."""
    keys = get_user_api_keys(user_id) or {}
    missing = []
    for f in PROFILE_REQUIRED_FIELDS:
        val = keys.get(f)
        if not val or not str(val).strip():
            missing.append((f, PROFILE_FIELD_LABELS.get(f, f)))
    return missing


def is_profile_complete(user_id):
    """Check if user has completed required profile fields."""
    return len(get_missing_profile_fields(user_id)) == 0

def get_user_domain_ids(user_id, is_admin=False):
    """Get list of domain IDs accessible by user."""
    if is_admin:
        with get_connection() as conn:
            cur = db_execute(conn, "SELECT id FROM domains")
            return [dict_row(r)["id"] for r in cur.fetchall()]
    with get_connection() as conn:
        cur = db_execute(conn, "SELECT domain_id FROM user_domains WHERE user_id = ?", (user_id,))
        return [dict_row(r)["domain_id"] for r in cur.fetchall()]

def get_user_group_ids(user_id, is_admin=False):
    """Get list of group IDs accessible by user (via user_groups table or their domains)."""
    if is_admin:
        with get_connection() as conn:
            cur = db_execute(conn, "SELECT id FROM `groups`")
            return [dict_row(r)["id"] for r in cur.fetchall()]
    
    with get_connection() as conn:
        # Get groups directly assigned to user
        cur = db_execute(conn, "SELECT group_id FROM user_groups WHERE user_id = ?", (user_id,))
        direct_groups = [dict_row(r)["group_id"] for r in cur.fetchall()]
        
        # Also get groups via domains (for backward compatibility)
        cur = db_execute(conn, """
            SELECT DISTINCT d.group_id 
            FROM user_domains ud
            JOIN domains d ON d.id = ud.domain_id
            WHERE ud.user_id = ? AND d.group_id IS NOT NULL
        """, (user_id,))
        domain_groups = [dict_row(r)["group_id"] for r in cur.fetchall()]
        
        # Combine and deduplicate
        all_groups = list(set(direct_groups + domain_groups))
        
        # Include all parent groups recursively
        def get_all_parents(gid):
            result = [gid]
            cur = db_execute(conn, "SELECT parent_group_id FROM `groups` WHERE id = ?", (gid,))
            row = dict_row(cur.fetchone())
            if row and row.get("parent_group_id"):
                result.extend(get_all_parents(row["parent_group_id"]))
            return result
        
        # Include all child groups recursively
        def get_all_children(gid):
            result = [gid]
            cur = db_execute(conn, "SELECT id FROM `groups` WHERE parent_group_id = ?", (gid,))
            children = [dict_row(r)["id"] for r in cur.fetchall()]
            for child_id in children:
                result.extend(get_all_children(child_id))
            return result
        
        # Expand to include parents and children
        expanded = set()
        for gid in all_groups:
            expanded.update(get_all_parents(gid))
            expanded.update(get_all_children(gid))
        
        return list(expanded)


def _ai_prompts_dict_from_profile_form(form):
    """Build ai_prompts_json dict from profile form fields. Empty = no profile overrides."""
    if not form:
        return None
    out = {}
    for json_key, form_key in (
        ("recipe_system", "ai_prompt_recipe_system"),
        ("recipe_user", "ai_prompt_recipe_user"),
        ("article_system", "ai_prompt_article_system"),
        ("article_user", "ai_prompt_article_user"),
        ("pin_prompt", "ai_prompt_pin_prompt"),
    ):
        v = (form.get(form_key) or "").strip()
        if v:
            out[json_key] = v
    fp = (form.get("ai_prompt_pin_field_prompts") or "").strip()
    if fp:
        try:
            parsed = json.loads(fp)
            if isinstance(parsed, dict):
                out["pin_field_prompts"] = parsed
        except json.JSONDecodeError:
            out["pin_field_prompts"] = {}
    return out if out else None


def _compute_group_prompt_overrides_from_form(form, user_id):
    """Only store keys changed from user's profile/base defaults (inherit-by-default)."""
    posted = _ai_prompts_dict_from_profile_form(form) or {}
    baseline = merge_prompt_layers(load_builtin_defaults(), parse_ai_prompts_json((get_user_api_keys(user_id) or {}).get("ai_prompts_json")), {})
    out = {}
    for key in ("recipe_system", "recipe_user", "article_system", "article_user", "pin_prompt"):
        pv = (posted.get(key) or "").strip()
        bv = (baseline.get(key) or "").strip()
        if pv and pv != bv:
            out[key] = pv
    if "pin_field_prompts" in posted and isinstance(posted.get("pin_field_prompts"), dict):
        pf = posted.get("pin_field_prompts") or {}
        bf = baseline.get("pin_field_prompts") if isinstance(baseline.get("pin_field_prompts"), dict) else {}
        if pf != bf:
            out["pin_field_prompts"] = pf
    return out if out else None


def user_can_edit_group_prompts(user_id, group_id, is_admin=False):
    if not group_id:
        return False
    if is_admin:
        return True
    try:
        gid = int(group_id)
    except (TypeError, ValueError):
        return False
    gids = get_user_group_ids(user_id, is_admin)
    return gid in (gids or [])


def get_user_config_for_api(user_id):
    """Get user's API configuration from database only."""
    keys = get_user_api_keys(user_id)
    
    # Build config dict with user keys
    config = {}
    
    # AI Provider
    config["ai_provider"] = keys.get("ai_provider")
    if not config["ai_provider"]:
        if keys.get("openrouter_api_key"):
            config["ai_provider"] = "openrouter"
        elif keys.get("groq_api_key"):
            config["ai_provider"] = "groq"
        else:
            config["ai_provider"] = "openai"
    
    # OpenAI
    config["openai_api_key"] = keys.get("openai_api_key")
    config["openai_model"] = keys.get("openai_model") or "gpt-4o-mini"
    
    # OpenRouter
    config["openrouter_api_key"] = _normalize_openrouter_api_key(keys.get("openrouter_api_key")) or None
    config["openrouter_model"] = keys.get("openrouter_model") or "openai/gpt-oss-120b"

    # Groq (OpenAI-compatible API)
    _gq_keys = parse_groq_api_keys(keys.get("groq_api_key"))
    config["groq_api_keys"] = _gq_keys
    config["groq_api_key"] = _gq_keys[0] if _gq_keys else None
    config["groq_model"] = keys.get("groq_model") or "llama-3.3-70b-versatile"
    
    # Fallback to provider based on available keys if standard provider key is missing
    if config["ai_provider"] == "openai" and not config["openai_api_key"] and config["openrouter_api_key"]:
        config["ai_provider"] = "openrouter"
    elif config["ai_provider"] == "openrouter" and not config["openrouter_api_key"] and config["openai_api_key"]:
        config["ai_provider"] = "openai"
    elif config["ai_provider"] == "openai" and not config["openai_api_key"] and config["groq_api_key"]:
        config["ai_provider"] = "groq"
    elif config["ai_provider"] == "groq" and not config["groq_api_key"] and config["openai_api_key"]:
        config["ai_provider"] = "openai"
    elif config["ai_provider"] == "groq" and not config["groq_api_key"] and config["openrouter_api_key"]:
        config["ai_provider"] = "openrouter"
    elif config["ai_provider"] == "local" and not config["local_api_url"]:
        if config["openrouter_api_key"]:
            config["ai_provider"] = "openrouter"
        elif config["groq_api_key"]:
            config["ai_provider"] = "groq"
        elif config["openai_api_key"]:
            config["ai_provider"] = "openai"
    elif config["ai_provider"] == "llamacpp":
        pass  # llamacpp uses llamacpp_manager_url, no key fallback

    if config["ai_provider"] == "openai" and not config["openai_api_key"]:
        if config["openrouter_api_key"]:
            config["ai_provider"] = "openrouter"
        elif config["groq_api_key"]:
            config["ai_provider"] = "groq"
    
    # Local
    config["local_api_url"] = keys.get("local_api_url") or "http://localhost:11434/api/generate"
    config["local_models"] = keys.get("local_models") or "qwen3:8b,llama3.2:3b"

    # llama.cpp (via llamacpp_manager)
    config["llamacpp_manager_url"] = keys.get("llamacpp_manager_url") or os.getenv("LLAMACPP_MANAGER_URL", LLAMACPP_MANAGER_URL or "http://localhost:5004")
    config["llamacpp_model_id"] = _parse_int_or_none(keys.get("llamacpp_model_id"))
    
    # Midjourney
    config["midjourney_api_token"] = keys.get("midjourney_api_token")
    config["midjourney_channel_id"] = keys.get("midjourney_channel_id")
    config["image_request_delay_sec"] = max(0, min(120, int(keys.get("image_request_delay_sec") or 15)))
    
    # R2
    config["r2_account_id"] = keys.get("r2_account_id")
    config["r2_access_key_id"] = keys.get("r2_access_key_id")
    config["r2_secret_access_key"] = keys.get("r2_secret_access_key")
    config["r2_bucket_name"] = keys.get("r2_bucket_name")
    config["r2_public_url"] = keys.get("r2_public_url")
    
    # Cloudflare (normalize so Bearer header is always valid for api.cloudflare.com)
    config["cloudflare_account_id"] = _normalize_cloudflare_account_id(keys.get("cloudflare_account_id")) or None
    config["cloudflare_api_token"] = _normalize_cloudflare_api_token(keys.get("cloudflare_api_token")) or None
    
    # Pinterest RSS (public base URL for feed - ngrok, deployed URL, etc.)
    config["rss_base_url"] = (keys.get("rss_base_url") or "").strip().rstrip("/") or None
    
    # Domains page: skip automatic Cloudflare/DNS status check on load
    config["skip_cf_status_check"] = keys.get("skip_cf_status_check")
    try:
        config["ui_poll_running_tasks"] = int(keys.get("ui_poll_running_tasks") or 0)
    except (TypeError, ValueError):
        config["ui_poll_running_tasks"] = 0
    try:
        config["ui_cf_auto_refresh_domains"] = int(keys.get("ui_cf_auto_refresh_domains") or 0)
    except (TypeError, ValueError):
        config["ui_cf_auto_refresh_domains"] = 0

    return config

def check_user_has_required_keys(user_id, operation_type="content"):
    """Check if user has required API keys for the operation."""
    config = get_user_config_for_api(user_id)
    
    if operation_type == "content":
        # Need at least one AI provider
        has_openai = bool(config.get("openai_api_key"))
        has_openrouter = bool(config.get("openrouter_api_key"))
        has_groq = bool(config.get("groq_api_key") or (config.get("groq_api_keys") or []))
        has_local = bool(config.get("local_api_url"))
        has_llamacpp = bool(config.get("llamacpp_manager_url"))
        return has_openai or has_openrouter or has_groq or has_local or has_llamacpp, "No AI provider configured. Please add OpenAI, OpenRouter, Groq, Local, or llama.cpp keys in your profile."
    
    elif operation_type == "image":
        # Need Midjourney
        has_midjourney = bool(config.get("midjourney_api_token") and config.get("midjourney_channel_id"))
        return has_midjourney, "Midjourney API keys not configured. Please add them in your profile."
    
    elif operation_type == "r2":
        # Need R2
        has_r2 = bool(config.get("r2_account_id") and config.get("r2_access_key_id") and config.get("r2_secret_access_key"))
        return has_r2, "Cloudflare R2 keys not configured. Please add them in your profile."
    
    elif operation_type == "cloudflare":
        # Need Cloudflare
        has_cf = bool(config.get("cloudflare_account_id") and config.get("cloudflare_api_token"))
        return has_cf, "Cloudflare API keys not configured. Please add them in your profile."
    
    return True, ""


def _hosted_images_public_base():
    """Base URL for locally hosted images (R2 fallback). Uses current request or PUBLIC_BASE_URL in .env."""
    try:
        if has_request_context() and request:
            return (request.url_root or "").rstrip("/")
    except Exception:
        pass
    from config import PUBLIC_BASE_URL

    return (PUBLIC_BASE_URL or "").strip().rstrip("/")


def _load_bulk_history():
    """Load persisted bulk job history from disk."""
    try:
        if not os.path.isfile(_BULK_HISTORY_PATH):
            return {}
        with open(_BULK_HISTORY_PATH, "r", encoding="utf-8") as f:
            data = json.load(f)
        return data if isinstance(data, dict) else {}
    except Exception:
        return {}


def _save_bulk_history(history):
    """Persist bulk job history to disk."""
    try:
        # Keep file bounded to newest 500 jobs.
        items = []
        for jid, p in (history or {}).items():
            if isinstance(p, dict):
                items.append((jid, p))
        items.sort(key=lambda kv: float((kv[1] or {}).get("created_at") or 0), reverse=True)
        trimmed = dict(items[:500])
        with open(_BULK_HISTORY_PATH, "w", encoding="utf-8") as f:
            json.dump(trimmed, f, ensure_ascii=False)
    except Exception:
        pass


_bulk_history = _load_bulk_history()

# On startup, any jobs that were left "running" in history are actually dead because the server restarted.
history_changed_on_startup = False
for jid, p in list(_bulk_history.items()):
    if isinstance(p, dict) and p.get("status") == "running":
        p["status"] = "error"
        p["message"] = "Server restarted"
        history_changed_on_startup = True

if history_changed_on_startup:
    _save_bulk_history(_bulk_history)


@app.route("/api/hosted-images/<path:prefix>/<filename>")
def hosted_image(prefix, filename):
    """Serve images stored when R2 is not configured (see r2_upload.save_bytes_local)."""
    from config import HOSTED_IMAGES_DIR

    if not re.match(r"^[a-zA-Z0-9_-]{1,80}$", prefix or ""):
        abort(404)
    if not re.match(r"^[a-fA-F0-9]{10,40}\.(png|jpg|jpeg|webp|bin)$", filename or "", re.I):
        abort(404)
    root = os.path.abspath(HOSTED_IMAGES_DIR)
    safe_dir = os.path.abspath(os.path.join(root, prefix))
    if os.path.commonpath([safe_dir, root]) != root or not os.path.isdir(safe_dir):
        abort(404)
    fp = os.path.join(safe_dir, filename)
    if not os.path.isfile(fp):
        abort(404)
    ext = (filename.rsplit(".", 1)[-1] or "").lower()
    mt = {
        "png": "image/png",
        "jpg": "image/jpeg",
        "jpeg": "image/jpeg",
        "webp": "image/webp",
    }.get(ext, "application/octet-stream")
    return send_from_directory(safe_dir, filename, mimetype=mt)


