@app.route("/database-management/rewrite", methods=["POST"])
def do_rewrite():
    article = request.form.get("article", "")
    result = rewrite(article)
    enc = base64.urlsafe_b64encode(json.dumps(result).encode()).decode()
    return redirect(url_for("database_management", r=enc))


def _parse_groq_model(req):
    """Parse groq_model from request dict or query. Return None or stripped model id."""
    v = (req.get("groq_model") or "").strip()
    return v or None


def _parse_openrouter_models(req):
    """Parse openrouter_models from request (list, JSON string, or comma-separated string). Return None or list of model ids."""
    raw = req.get("openrouter_models")
    if raw is None:
        return None
    if isinstance(raw, list):
        return [str(m).strip() for m in raw if str(m).strip()] or None
    s = (raw if isinstance(raw, str) else str(raw)).strip()
    if not s:
        return None
    if s.startswith("["):
        try:
            parsed = json.loads(s)
            if isinstance(parsed, list):
                return [str(m).strip() for m in parsed if str(m).strip()] or None
        except json.JSONDecodeError:
            pass
    return [x.strip() for x in s.split(",") if x.strip()] or None


def _parse_content_ai_params(req):
    """Parse AI provider/model fields from a request dict (JSON body + query). Resolves openrouter_model from openrouter_models when needed."""
    ai_provider = (str(req.get("ai_provider") or "").strip() or None)
    openrouter_models = _parse_openrouter_models(req)
    openai_model = (str(req.get("openai_model") or "").strip() or None)
    openrouter_model = (str(req.get("openrouter_model") or "").strip() or None)
    if not openrouter_model and openrouter_models:
        openrouter_model = openrouter_models[0]
    local_model = (str(req.get("local_model") or "").strip() or None)
    groq_model = _parse_groq_model(req)
    llamacpp_model_id = req.get("llamacpp_model_id")
    if llamacpp_model_id is not None and str(llamacpp_model_id).strip():
        try:
            llamacpp_model_id = int(llamacpp_model_id)
        except (TypeError, ValueError):
            llamacpp_model_id = None
    else:
        llamacpp_model_id = None
    return {
        "ai_provider": ai_provider,
        "openai_model": openai_model,
        "openrouter_model": openrouter_model,
        "openrouter_models": openrouter_models,
        "local_model": local_model,
        "groq_model": groq_model,
        "llamacpp_model_id": llamacpp_model_id,
    }


def _pin_ai_kwargs_from_params(ai_provider, openai_model, openrouter_model, groq_model, local_model, llamacpp_model_id):
    """Keyword args for _do_generate_pin_image (pin template text); omit Nones."""
    out = {}
    if ai_provider:
        out["ai_provider"] = ai_provider
    if openai_model:
        out["openai_model"] = openai_model
    if openrouter_model:
        out["openrouter_model"] = openrouter_model
    if groq_model:
        out["groq_model"] = groq_model
    if local_model:
        out["local_model"] = local_model
    if llamacpp_model_id is not None:
        out["llamacpp_model_id"] = llamacpp_model_id
    return out


def _do_generate_article_external(title_id, recipe_from_a=None, ai_provider=None, openrouter_models=None, openai_model=None, openrouter_model=None, local_model=None, llamacpp_model_id=None, groq_model=None, user_id=None):
    """Call external API http://localhost:5002/generate-article/{website_template} and save to article_content.
    Requires main_image and ingredient_image to exist (generate images first).
    When recipe_from_a is provided (from Domain A), B/C/D use it to generate from recipe instead of from title.
    ai_provider: optional override (openrouter, openai, groq, local, llamacpp).
    openrouter_models: optional list of OpenRouter model ids to use (rotation over this list). If None, generator uses its full list.
    openai_model: optional OpenAI model id (e.g. gpt-4o-mini) when ai_provider=openai; overrides profile default.
    openrouter_model: optional OpenRouter default model id when ai_provider=openrouter; overrides profile default.
    groq_model: optional Groq model id when ai_provider=groq; overrides profile default.
    local_model: optional Local model id (e.g., qwen3:8b) when ai_provider=local.
    llamacpp_model_id: optional model id (int) when ai_provider=llamacpp.
    user_id: optional user ID to use user-specific API keys."""
    with get_connection() as conn:
        cur = db_execute(conn, """SELECT t.id, t.title, t.domain_id
            FROM titles t WHERE t.id = ?""", (title_id,))
        row = dict_row(cur.fetchone())
        if not row:
            raise ValueError("Title not found")
        title_text = (row.get("title") or "").strip()
        domain_id = row.get("domain_id")
        if not domain_id:
            raise ValueError("Title has no domain")
        cur = db_execute(conn, "SELECT website_template, categories_list, article_template_config, domain_colors, domain_fonts, writers, last_writer_index, domain_index, group_id FROM domains WHERE id = ?", (domain_id,))
        d = dict_row(cur.fetchone())
        template = (d.get("website_template") or "").strip()
        domain_index = d.get("domain_index")
        group_id = d.get("group_id")
        if not template:
            raise ValueError("Domain has no website_template. Set it in Admin Domains.")
        categories_raw = (d.get("categories_list") or "").strip()
        categories_list = []
        if categories_raw:
            try:
                categories_list = json.loads(categories_raw)
                if not isinstance(categories_list, list):
                    categories_list = []
            except json.JSONDecodeError:
                pass
        ac_row = None
        cur = db_execute(conn, """SELECT main_image, ingredient_image, top_image, bottom_image, avatar_image, pin_image
            FROM article_content WHERE title_id = ? AND language_code = 'en'""", (title_id,))
        ac_row = dict_row(cur.fetchone())
        main_ok = bool(ac_row and (ac_row.get("main_image") or "").strip().startswith("http"))
        ing_ok = bool(ac_row and (ac_row.get("ingredient_image") or "").strip().startswith("http"))
        if not main_ok:
            raise ValueError("Generate main image first")
        if not ing_ok:
            raise ValueError("Generate ingredient image first")
    IMAGE_FIELDS = ("main_image", "ingredient_image", "top_image", "bottom_image", "avatar_image", "pin_image")
    IMAGE_TO_CONFIG = {"main_image": "main_article_image", "ingredient_image": "ingredient_image", "top_image": "top_image", "bottom_image": "bottom_image", "avatar_image": "avatar_image"}
    base = (GENERATE_ARTICLE_API_URL or "").rstrip("/")
    url = f"{base}/generate-article/{template}"
    payload = {"title": title_text, "title_id": int(title_id)}
    user_config = {}

    # Add user-specific API keys to payload
    if not user_id:
        log.warning("[generate-article-external] user_id is None — API keys will not be sent. Add keys in Profile.")
    if user_id:
        user_config = get_user_config_for_api(user_id)
        # Add API keys to payload so external generator can use them
        if user_config.get("openai_api_key"):
            payload["openai_api_key"] = user_config["openai_api_key"]
            payload["openai_model"] = (openai_model and str(openai_model).strip()) or user_config.get("openai_model") or "gpt-4o-mini"
        if user_config.get("openrouter_api_key"):
            payload["openrouter_api_key"] = user_config["openrouter_api_key"]
            payload["openrouter_model"] = (openrouter_model and str(openrouter_model).strip()) or user_config.get("openrouter_model") or "openai/gpt-oss-120b"
        _gq_list = user_config.get("groq_api_keys") or []
        if _gq_list:
            payload["groq_api_keys"] = list(_gq_list)
            payload["groq_api_key"] = _gq_list[0]
            payload["groq_model"] = (groq_model and str(groq_model).strip()) or user_config.get("groq_model") or "llama-3.3-70b-versatile"
        if user_config.get("local_api_url"):
            payload["local_api_url"] = user_config["local_api_url"]
        if user_config.get("local_models"):
            payload["local_models"] = user_config["local_models"]
        if user_config.get("llamacpp_manager_url"):
            payload["llamacpp_manager_url"] = user_config["llamacpp_manager_url"]
        if user_config.get("llamacpp_model_id") is not None:
            payload["llamacpp_model_id"] = int(user_config["llamacpp_model_id"])
        # Use caller's ai_provider (e.g. from Run all groups modal) when passed; otherwise fall back to profile
        if ai_provider and str(ai_provider).strip():
            payload["ai_provider"] = str(ai_provider).strip().lower()
        elif user_config.get("ai_provider"):
            ai_provider = user_config.get("ai_provider")
            payload["ai_provider"] = user_config["ai_provider"]
        elif user_config.get("openai_api_key") and not user_config.get("openrouter_api_key") and not user_config.get("groq_api_key"):
            ai_provider = "openai"
            payload["ai_provider"] = "openai"
        elif user_config.get("openrouter_api_key") and not user_config.get("openai_api_key") and not user_config.get("groq_api_key"):
            ai_provider = "openrouter"
            payload["ai_provider"] = "openrouter"
        elif user_config.get("groq_api_key") and not user_config.get("openai_api_key") and not user_config.get("openrouter_api_key"):
            ai_provider = "groq"
            payload["ai_provider"] = "groq"

    if ai_provider and str(ai_provider).strip():
        payload["ai_provider"] = str(ai_provider).strip().lower()
    has_openai = bool(payload.get("openai_api_key"))
    has_openrouter = bool(payload.get("openrouter_api_key"))
    has_groq = bool(payload.get("groq_api_key") or (payload.get("groq_api_keys") or []))
    log.info("[generate-article-external] title_id=%s ai_provider=%s has_openai_key=%s has_openrouter_key=%s has_groq_key=%s", title_id, payload.get("ai_provider"), has_openai, has_openrouter, has_groq)
    if "ai_provider" not in payload or not payload["ai_provider"]:
        if payload.get("openrouter_api_key") and not payload.get("openai_api_key") and not payload.get("groq_api_key"):
            payload["ai_provider"] = "openrouter"
        elif payload.get("groq_api_key") and not payload.get("openai_api_key") and not payload.get("openrouter_api_key"):
            payload["ai_provider"] = "groq"
        elif payload.get("openai_api_key") and not payload.get("openrouter_api_key") and not payload.get("groq_api_key"):
            payload["ai_provider"] = "openai"

    # Require API keys from Profile when using cloud providers (do not fall back to generator .env)
    provider = (payload.get("ai_provider") or "").strip().lower()
    if provider == "openai" and not payload.get("openai_api_key"):
        if not user_id:
            raise ValueError("Login required. API keys are read from your Profile (multi-domain-clean). Log in and try again.")
        raise ValueError("Add your OpenAI API key in Profile (multi-domain-clean → Profile). The generator does not use its own .env when you run from here.")
    if provider == "openrouter" and not payload.get("openrouter_api_key"):
        if not user_id:
            raise ValueError("Login required. API keys are read from your Profile (multi-domain-clean). Log in and try again.")
        raise ValueError("Add your OpenRouter API key in Profile (multi-domain-clean → Profile). The generator does not use its own .env when you run from here.")
    if provider == "groq" and not payload.get("groq_api_key"):
        if not user_id:
            raise ValueError("Login required. API keys are read from your Profile (multi-domain-clean). Log in and try again.")
        raise ValueError("Add your Groq API key in Profile (https://console.groq.com/keys). The generator does not use its own .env when you run from here.")
    if provider == "llamacpp":
        if not payload.get("llamacpp_manager_url"):
            raise ValueError("llamacpp_manager_url not configured. Set LLAMACPP_MANAGER_URL in .env or Profile.")
        # Use explicit model id from request, or fall back to Profile default
        if llamacpp_model_id is None and user_id:
            llamacpp_model_id = payload.get("llamacpp_model_id")
        if llamacpp_model_id is None:
            raise ValueError("Select a llama.cpp model in the Run modal, or set Default model in Profile.")
        payload["llamacpp_model_id"] = int(llamacpp_model_id)
    if openrouter_models is not None and isinstance(openrouter_models, list) and len(openrouter_models) > 0:
        payload["openrouter_models"] = [str(m).strip() for m in openrouter_models if str(m).strip()]
    if openai_model and str(openai_model).strip() and payload.get("openai_api_key"):
        payload["openai_model"] = str(openai_model).strip()
    if openrouter_model and str(openrouter_model).strip() and payload.get("openrouter_api_key"):
        payload["openrouter_model"] = str(openrouter_model).strip()
    if groq_model and str(groq_model).strip() and payload.get("groq_api_key"):
        payload["groq_model"] = str(groq_model).strip()
    if local_model and str(local_model).strip():
        payload["local_model"] = str(local_model).strip()
    if user_config.get("llamacpp_manager_url"):
        payload["llamacpp_manager_url"] = user_config["llamacpp_manager_url"]
    if llamacpp_model_id is not None:
        payload["llamacpp_model_id"] = int(llamacpp_model_id)
    elif payload.get("llamacpp_model_id") is not None:
        payload["llamacpp_model_id"] = int(payload["llamacpp_model_id"])
    if domain_index is not None:
        payload["domain_index"] = int(domain_index) if isinstance(domain_index, (int, float)) else 0
    if group_id is not None:
        payload["group_id"] = int(group_id) if isinstance(group_id, (int, float)) else 0
    if user_id:
        payload["ai_prompts"] = get_effective_ai_prompts(user_id, group_id)
    if categories_list:
        payload["categories_list"] = categories_list
    if ac_row:
        images_config = {}
        for f in IMAGE_FIELDS:
            val = (ac_row.get(f) or "").strip()
            if val and (val.startswith("http") or val.startswith("//")):
                payload[f] = val
                cfg_key = IMAGE_TO_CONFIG.get(f)
                if cfg_key:
                    images_config[cfg_key] = val
        if "main_article_image" not in images_config and payload.get("main_image"):
            images_config["main_article_image"] = payload["main_image"]
        if "ingredient_image" not in images_config and payload.get("ingredient_image"):
            images_config["ingredient_image"] = payload["ingredient_image"]
        if "recipe_card_image" not in images_config and payload.get("main_image"):
            images_config["recipe_card_image"] = payload["main_image"]
        elif "recipe_card_image" not in images_config and payload.get("ingredient_image"):
            images_config["recipe_card_image"] = payload["ingredient_image"]
        if images_config:
            payload.setdefault("images", {})
            if isinstance(payload.get("images"), dict):
                payload["images"].update(images_config)
            else:
                payload["images"] = images_config
    cfg_raw = (d.get("article_template_config") or "").strip()
    if cfg_raw:
        try:
            domain_config = json.loads(cfg_raw) if isinstance(cfg_raw, str) else cfg_raw
            if isinstance(domain_config, dict):
                for k, v in domain_config.items():
                    if k not in payload:
                        payload[k] = v
        except json.JSONDecodeError:
            pass
    # Merge domain_colors for articles (primary, secondary, etc.)
    dc_raw = (d.get("domain_colors") or "").strip()
    if dc_raw:
        try:
            dc = json.loads(dc_raw) if isinstance(dc_raw, str) else dc_raw
            if isinstance(dc, dict):
                payload.setdefault("colors", {})
                if isinstance(payload.get("colors"), dict):
                    for k, v in dc.items():
                        if v:
                            payload["colors"][k] = v
        except json.JSONDecodeError:
            pass
    if "colors" not in payload or not payload.get("colors"):
        payload["colors"] = dict(DEFAULT_DOMAIN_COLORS)
    # Merge domain_fonts for articles (heading, body)
    df_raw = (d.get("domain_fonts") or "").strip()
    if df_raw:
        try:
            fonts_cfg = _domain_fonts_to_config(df_raw)
            payload.setdefault("fonts", {})
            if isinstance(payload.get("fonts"), dict):
                for k, v in fonts_cfg.items():
                    if v:
                        payload["fonts"][k] = v
        except Exception:
            pass
    
    # Writer rotation: pick next writer from domain's writers list
    writers_raw = (d.get("writers") or "").strip()
    if writers_raw:
        try:
            writers = json.loads(writers_raw) if isinstance(writers_raw, str) else writers_raw
            if isinstance(writers, list) and len(writers) > 0:
                last_idx = d.get("last_writer_index") or 0
                next_idx = (last_idx + 1) % len(writers)
                writer = writers[next_idx]
                if isinstance(writer, dict):
                    payload["writer"] = {
                        "name": writer.get("name", ""),
                        "title": writer.get("title", ""),
                        "bio": writer.get("bio", ""),
                        "avatar": writer.get("avatar", "")
                    }
                    # Update last_writer_index for next article
                    with get_connection() as conn2:
                        db_execute(conn2, "UPDATE domains SET last_writer_index = ? WHERE id = ?", (next_idx, domain_id))
        except json.JSONDecodeError:
            pass
    if recipe_from_a is not None:
        if isinstance(recipe_from_a, dict):
            payload["recipe"] = recipe_from_a
        elif isinstance(recipe_from_a, str) and recipe_from_a.strip():
            try:
                payload["recipe"] = json.loads(recipe_from_a)
            except json.JSONDecodeError:
                pass
    
    _enforce_pinterest_pin_color(payload)
    _MAX_RETRIES = 3
    use_openrouter = (payload.get("ai_provider") or "").strip().lower() == "openrouter"
    _groq_keys_list = [str(x).strip() for x in (payload.get("groq_api_keys") or []) if str(x).strip()]
    use_groq = (payload.get("ai_provider") or "").strip().lower() == "groq" and bool(_groq_keys_list)
    use_groq_multi = use_groq and len(_groq_keys_list) > 3
    _groq_extra_starts = list(range(3, len(_groq_keys_list), 3)) if use_groq_multi else []
    base_groq_idx = (int(title_id) % len(_groq_keys_list)) if _groq_keys_list else 0
    # Build a full ordered fallback model list for OpenRouter rotation.
    # Start with whatever the user explicitly selected, then append all remaining models from
    # OPENROUTER_MODELS so we cycle through every available model before giving up.
    _all_or_ids = [m["id"] for m in OPENROUTER_MODELS]
    if use_openrouter:
        _selected = []
        if payload.get("openrouter_models") and isinstance(payload["openrouter_models"], list):
            _selected = [str(m).strip() for m in payload["openrouter_models"] if str(m).strip()]
        elif payload.get("openrouter_model") and str(payload["openrouter_model"]).strip():
            _selected = [str(payload["openrouter_model"]).strip()]
        if _selected:
            # Put user's selection(s) first, then all others not already included
            _rest = [m for m in _all_or_ids if m not in _selected]
            _rotation_list = _selected + _rest
        else:
            _rotation_list = _all_or_ids
        payload["openrouter_models"] = _rotation_list
        # Retry starts: each round advances by 3 so each round tries 3 new models
        # (route.py OPENROUTER_RETRY_OFFSETS=[0,5,10] but we're sending full list now)
        # We advance start_index by 3 each round to cover all models: 0,3,6,9,12,15 → 6 rounds = 18 attempts across 16 models (with wrap)
        _openrouter_extra_starts = list(range(3, len(_rotation_list), 3))  # [3, 6, 9, 12, 15]
        log.info("[generate-article-external] openrouter rotation list (%s models): %s", len(_rotation_list), _rotation_list[:3])
    else:
        _openrouter_extra_starts = []
    _num_extra_rounds = len(_openrouter_extra_starts) if use_openrouter else (len(_groq_extra_starts) if use_groq_multi else 0)
    out = None
    t0 = time.time()
    for _round in range(1 + _num_extra_rounds):
        if use_openrouter:
            # Always set openrouter_start_index so route.py uses our ordered list from index 0
            # Round 0 → index 0 (user's pick first), round 1 → index 3, round 2 → index 6, ...
            start_idx = 0 if _round == 0 else _openrouter_extra_starts[_round - 1]
            payload["openrouter_start_index"] = start_idx
            _model_at = _rotation_list[start_idx % len(_rotation_list)]
            if _round == 0:
                log.info("[generate-article-external] round 1/%s start_idx=0 first_model=%s", 1 + len(_openrouter_extra_starts), _model_at)
            else:
                log.warning("[generate-article-external] retry round %s/%s start_idx=%s model=%s", _round + 1, 1 + len(_openrouter_extra_starts), start_idx, _model_at)
        else:
            payload.pop("openrouter_start_index", None)
        if use_groq and _groq_keys_list:
            shift = 0 if _round == 0 else (_groq_extra_starts[_round - 1] if use_groq_multi else 0)
            payload["groq_start_index"] = (base_groq_idx + shift) % len(_groq_keys_list)
            log.info(
                "[generate-article-external] groq round %s/%s keys=%s start_index=%s",
                _round + 1,
                1 + _num_extra_rounds,
                len(_groq_keys_list),
                payload["groq_start_index"],
            )
        body = json.dumps(payload).encode("utf-8")
        req = urllib.request.Request(url, data=body, method="POST", headers={"Content-Type": "application/json"})
        log.info("[generate-article-external] payload url=%s round=%s", url, _round + 1)
        for _attempt in range(_MAX_RETRIES + 1):
            try:
                with urllib.request.urlopen(req, timeout=360) as resp:  # 6 min - generator does multiple OpenAI calls
                    raw = resp.read().decode()
                    out = json.loads(raw)
                keys = list(out.keys()) if isinstance(out, dict) else []
                log.info("[generate-article-external] response keys=%s", keys)
                resp_log = {}
                for k, v in (out or {}).items():
                    if isinstance(v, str) and len(v) > 200:
                        resp_log[k] = f"<str len={len(v)} preview={repr(v[:100])}...>"
                    elif isinstance(v, (dict, list)):
                        resp_log[k] = f"<{type(v).__name__} len={len(v)}>"
                    else:
                        resp_log[k] = v
                log.info("[generate-article-external] response=%s", json.dumps(resp_log, ensure_ascii=False, default=str)[:2000])
                break  # success — exit attempt loop
            except urllib.error.HTTPError as e:
                err_body = e.read().decode(errors="replace") if e.fp else str(e)
                log.error(
                    "[generate-article-external] HTTP %s url=%s template=%s response (first 4000 chars): %s",
                    e.code,
                    url,
                    template,
                    err_body[:4000],
                )
                log.warning("[generate-article-external] external API HTTP %s response: %s", e.code, err_body[:1500])
                if e.code == 401 or "invalid_api_key" in err_body.lower() or "incorrect api key" in err_body.lower():
                    _app_log("article", False, "API key invalid or expired", reason=err_body[:300], title_id=title_id)
                    raise ValueError(
                        "API key invalid or expired. Update your OpenAI (or OpenRouter) key in multi-domain-clean → Profile and try again. "
                        "Keys are read from your Profile, not from the generator's .env."
                    )
                if "insufficient_quota" in err_body or "quota" in err_body.lower():
                    _app_log("article", False, f"OpenAI quota exceeded (HTTP {e.code})", reason=err_body[:300], title_id=title_id)
                    raise ValueError(f"OpenAI quota exceeded — check billing. HTTP {e.code}: {err_body[:300]}")
                # 400 "Content generation failed after 3 attempt(s)": advance to next OpenRouter model set or Groq key block
                if e.code == 400 and "Content generation failed" in err_body:
                    if use_openrouter and _round < len(_openrouter_extra_starts):
                        log.warning("[generate-article-external] 400 after 3 attempts (OpenRouter), retrying with different model set (round %s)", _round + 2)
                        break  # exit attempt loop, continue to next _round
                    if use_groq_multi and _round < len(_groq_extra_starts):
                        log.warning("[generate-article-external] 400 after 3 attempts (Groq keys), retrying next key block (round %s)", _round + 2)
                        break
                if _attempt < _MAX_RETRIES and (e.code >= 500 or e.code in (408, 429)):
                    wait = (_attempt + 1) * 10
                    log.warning("[generate-article-external] retry %d/%d after HTTP %s, waiting %ds...", _attempt + 1, _MAX_RETRIES, e.code, wait)
                    time.sleep(wait)
                    req = urllib.request.Request(url, data=body, method="POST", headers={"Content-Type": "application/json"})
                    continue
                _summ = _summarize_article_generator_http_error_body(err_body)
                _app_log("article", False, f"Article generator HTTP {e.code} {url}", reason=_summ[:500], title_id=title_id)
                raise ValueError(
                    "Article generator returned HTTP "
                    + str(e.code)
                    + " for POST "
                    + url
                    + " (domain template "
                    + repr(template)
                    + "). Body: "
                    + _summ
                    + " — The real Python traceback is on the articles-website-generator process (GENERATE_ARTICLE_API_URL, e.g. localhost:5002), not in multi-domain-clean logs."
                )
            except (urllib.error.URLError, OSError) as e:
                log.warning("[generate-article-external] connection/timeout error: %s", e)
                if _attempt < _MAX_RETRIES:
                    wait = (_attempt + 1) * 10
                    log.warning("[generate-article-external] retry %d/%d, waiting %ds...", _attempt + 1, _MAX_RETRIES, wait)
                    time.sleep(wait)
                    req = urllib.request.Request(url, data=body, method="POST", headers={"Content-Type": "application/json"})
                    continue
                _app_log("article", False, f"API unreachable after {_MAX_RETRIES} retries: {e}", title_id=title_id)
                raise ValueError(f"External API unreachable after {_MAX_RETRIES} retries: {e}")
        if out is not None:
            break
    if out is None:
        raise ValueError("External API returned no data after retries")

    article_html = (out.get("article_html") or out.get("article") or
                    (out.get("data") or {}).get("article_html") or (out.get("data") or {}).get("article") or "")
    if not isinstance(article_html, str):
        article_html = str(article_html) if article_html else ""
    article_html = article_html.strip()
    log.info("[generate-article-external] article_html len=%s (has_html=%s)", len(article_html), article_html.startswith("<") if article_html else False)
    if not article_html and isinstance(out, dict):
        log.warning("[generate-article-external] article_html EMPTY - response keys: %s", list(out.keys()))
    recipe = out.get("recipe")
    recipe_str = json.dumps(recipe, ensure_ascii=False) if isinstance(recipe, dict) else (recipe or "")
    # prompt and prompt_image_ingredients come from generate-prompts step only; never overwrite from article generator
    prompt = ""
    prompt_ing = ""
    with get_connection() as conn:
        cur = db_execute(conn, "SELECT prompt, prompt_image_ingredients FROM article_content WHERE title_id = ? AND language_code = 'en'", (title_id,))
        row = dict_row(cur.fetchone())
        if row:
            prompt = (row.get("prompt") or "").strip()
            prompt_ing = (row.get("prompt_image_ingredients") or "").strip()
    article_css = (out.get("article_css") or out.get("content_css") or
                  (out.get("data") or {}).get("article_css") or (out.get("data") or {}).get("content_css") or "")
    if not isinstance(article_css, str):
        article_css = str(article_css) if article_css else ""
    article_css = article_css.strip()
    log.info("[generate-article-external] article_css len=%s", len(article_css))
    
    # Inject writer HTML at top of article if writer_template is set
    if article_html and payload.get("writer"):
        with get_connection() as conn:
            cur = db_execute(conn, "SELECT writer_template, domain_colors, article_template_config FROM domains WHERE id = ?", (domain_id,))
            dom = dict_row(cur.fetchone())
            writer_tpl = (dom.get("writer_template") or "").strip()
            if writer_tpl:
                log.info(f"[generate-article-external] Injecting writer template: {writer_tpl}")
                # Build config for writer template
                writer_config = {"writer": payload["writer"]}
                # Add colors
                dc_raw = (dom.get("domain_colors") or "").strip()
                if dc_raw:
                    try:
                        dc = json.loads(dc_raw)
                        if isinstance(dc, dict):
                            writer_config["colors"] = dc
                    except:
                        pass
                if "colors" not in writer_config:
                    writer_config["colors"] = dict(DEFAULT_DOMAIN_COLORS)
                # Fetch writer HTML/CSS from website-parts-generator
                writer_part = _fetch_site_part_internal("writer", writer_tpl, writer_config)
                if writer_part and writer_part.get("html"):
                    writer_html = writer_part["html"]
                    writer_css = writer_part.get("css", "")
                    
                    # NOTE: Article generators produce single-column HTML without sidebar
                    # The sidebar is added by the preview-website system when displaying
                    # So we DON'T inject writer into article_html here
                    # Instead, we just save the writer data to article_content table
                    # The preview-website will handle injecting writer into sidebar-area
                    
                    log.info(f"[generate-article-external] Writer data prepared (will be injected by preview-website into sidebar)")
                    
                    # Append writer CSS to article CSS for when it's used
                    if writer_css:
                        article_css = article_css + "\n\n/* Writer Byline */\n" + writer_css
    
    def _valid_url(v):
        s = (v or "").strip()
        return s if s and (s.startswith("http") or s.startswith("//")) else ""

    main_img = _valid_url(out.get("main_image"))
    ing_img = _valid_url(out.get("ingredient_image"))
    top_img = _valid_url(out.get("top_image"))
    bottom_img = _valid_url(out.get("bottom_image"))
    avatar_img = _valid_url(out.get("avatar_image"))

    # Preserve existing image URLs if generator returned empty/placeholder
    existing_imgs = {}
    with get_connection() as conn:
        cur = db_execute(conn, "SELECT main_image, ingredient_image, top_image, bottom_image, avatar_image FROM article_content WHERE title_id = ? AND language_code = 'en'", (title_id,))
        row = dict_row(cur.fetchone())
        if row:
            for k in ("main_image", "ingredient_image", "top_image", "bottom_image", "avatar_image"):
                existing_imgs[k] = _valid_url(row.get(k))
    if not main_img and existing_imgs.get("main_image"):
        main_img = existing_imgs["main_image"]
    if not ing_img and existing_imgs.get("ingredient_image"):
        ing_img = existing_imgs["ingredient_image"]
    if not top_img and existing_imgs.get("top_image"):
        top_img = existing_imgs["top_image"]
    if not bottom_img and existing_imgs.get("bottom_image"):
        bottom_img = existing_imgs["bottom_image"]
    if not avatar_img and existing_imgs.get("avatar_image"):
        avatar_img = existing_imgs["avatar_image"]

    model_used = (out.get("model_used") or "").strip()
    generated_at = datetime.utcnow().strftime("%Y-%m-%d %H:%M:%S")
    generation_time_seconds = int(round(time.time() - t0))
    # Cost/usage from OpenAI or OpenRouter (generator may return usage and/or generation_cost_usd)
    usage_raw = out.get("usage")
    if isinstance(usage_raw, dict):
        usage_json_str = json.dumps(usage_raw, ensure_ascii=False)
    else:
        usage_json_str = (usage_raw or "").strip() if isinstance(usage_raw, str) else ""
    cost_val = out.get("generation_cost_usd")
    if cost_val is None and isinstance(usage_raw, dict):
        cost_val = usage_raw.get("cost")
    if cost_val is not None:
        try:
            cost_val = float(cost_val)
        except (TypeError, ValueError):
            cost_val = None
    
    # Prepare writer data for saving
    writer_json = ""
    writer_avatar_url = ""
    if payload.get("writer"):
        writer_json = json.dumps(payload["writer"])
        writer_avatar_url = payload["writer"].get("avatar", "")
    
    vals = (
        article_html, recipe_str, prompt, prompt_ing,
        out.get("recipe_title_pin", ""), out.get("pinterest_title", ""), out.get("pinterest_description", ""),
        out.get("pinterest_keywords", ""), out.get("focus_keyphrase", ""), out.get("meta_description", ""),
        out.get("keyphrase_synonyms", ""), article_css,
        main_img, ing_img, top_img, bottom_img, avatar_img,
        writer_json, writer_avatar_url, model_used, generated_at, generation_time_seconds,
        cost_val, usage_json_str, title_id
    )
    with get_connection() as conn:
        cur = db_execute(conn, "SELECT id FROM article_content WHERE title_id = ? AND language_code = 'en'", (title_id,))
        if cur.fetchone():
            db_execute(conn, """UPDATE article_content SET article_html=?, article=?, recipe=?, prompt=?, prompt_image_ingredients=?,
                recipe_title_pin=?, pinterest_title=?, pinterest_description=?, pinterest_keywords=?,
                focus_keyphrase=?, meta_description=?, keyphrase_synonyms=?, article_css=?,
                main_image=?, ingredient_image=?, top_image=?, bottom_image=?, avatar_image=?,
                writer=?, writer_avatar=?, model_used=?, generated_at=?, generation_time_seconds=?,
                generation_cost_usd=?, usage_json=?
                WHERE title_id=? AND language_code='en'""", (vals[0],) + vals)
        else:
            db_execute(conn, """INSERT INTO article_content (title_id, language_code, article_html, article, recipe, prompt, prompt_image_ingredients,
                recipe_title_pin, pinterest_title, pinterest_description, pinterest_keywords, focus_keyphrase, meta_description, keyphrase_synonyms, article_css,
                main_image, ingredient_image, top_image, bottom_image, avatar_image, writer, writer_avatar, model_used, generated_at, generation_time_seconds, generation_cost_usd, usage_json)
                VALUES (?, 'en', ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)""",
                (title_id, vals[0]) + vals[:-1])
    _update_article_html_images(title_id)
    _update_article_html_pin_image(title_id)
    return article_html, article_css


