def _get_ai_provider_models_from_db(provider):
    """Return models from ai_provider_models table. Falls back to code constants if empty."""
    try:
        with get_connection() as conn:
            cur = db_execute(conn, "SELECT model_id, label, is_free, sort_order FROM ai_provider_models WHERE provider = ? ORDER BY sort_order, id", (provider,))
            rows = cur.fetchall()
        if not rows:
            return None
        out = []
        for r in (dict_row(row) for row in rows):
            item = {"id": (r.get("model_id") or "").strip(), "label": (r.get("label") or r.get("model_id") or "").strip(), "free": bool(r.get("is_free"))}
            out.append(item)
        return out
    except Exception:
        return None


def _merged_openrouter_model_options():
    """DB models plus any OPENROUTER_MODELS ids missing from DB (same merge as /api/openrouter-models)."""
    db_models = _get_ai_provider_models_from_db("openrouter")
    if not db_models:
        return [dict(m) for m in OPENROUTER_MODELS]
    db_ids = {m["id"] for m in db_models}
    merged = list(db_models)
    for cm in OPENROUTER_MODELS:
        if cm["id"] not in db_ids:
            merged.append({"id": cm["id"], "label": cm["label"], "free": cm.get("free", False)})
    return merged


