@app.route("/api/domains", methods=["GET"])
def api_domains_list():
    """List domains (id, domain_url, website_template) for article-editor dropdown."""
    with get_connection() as conn:
        cur = db_execute(conn, "SELECT id, domain_url, domain_name, website_template FROM domains ORDER BY id")
        rows = [dict_row(r) for r in cur.fetchall()]
    return jsonify({"domains": rows})


@app.route("/api/domains/<int:pk>", methods=["GET", "PUT"])
def api_domain_get(pk):
    """GET: Return domain by id (domain_url). PUT: Update domain_url (domain_name synced to domain_url)."""
    if request.method == "PUT":
        data = request.get_json(silent=True) or {}
        raw = (data.get("domain_url") or "").strip()
        url = _normalize_domain(raw) or None
        if not url:
            return jsonify({"success": False, "error": "Domain URL is required"}), 400
        # Duplicate check (exclude self)
        with get_connection() as conn:
            cur = db_execute(conn, "SELECT id FROM domains WHERE domain_url = ? AND id != ?", (url, pk))
            if cur.fetchone():
                return jsonify({"success": False, "error": f"'{url}' is already in the database"}), 409
            db_execute(conn, "UPDATE domains SET domain_url = ?, domain_name = ? WHERE id = ?", (url, url, pk))
        return jsonify({"success": True, "id": pk, "domain_url": url})
    with get_connection() as conn:
        cur = db_execute(conn, "SELECT id, domain_url, domain_name, domain_colors, domain_fonts, pinterest_board_id, pinterest_boards, pinterest_access_token, pinterest_app_id, pinterest_app_secret, pinterest_mode, pinterest_domain_verify FROM domains WHERE id = ?", (pk,))
        row = dict_row(cur.fetchone())
    if not row:
        return jsonify({"error": "Domain not found"}), 404
    dc = {}
    raw_c = (row.get("domain_colors") or "").strip()
    if raw_c:
        try:
            dc = json.loads(raw_c) if isinstance(raw_c, str) else raw_c
        except (json.JSONDecodeError, TypeError):
            pass
    df = {}
    raw_f = (row.get("domain_fonts") or "").strip()
    if raw_f:
        try:
            df = json.loads(raw_f) if isinstance(raw_f, str) else raw_f
        except (json.JSONDecodeError, TypeError):
            pass
    out = {"id": row["id"], "domain_url": row.get("domain_url") or "", "domain_name": row.get("domain_name") or "", "domain_colors": dc, "domain_fonts": df}
    out["pinterest_board_id"] = (row.get("pinterest_board_id") or "").strip()
    out["pinterest_app_id"] = (row.get("pinterest_app_id") or "").strip()
    out["pinterest_app_secret_set"] = bool((row.get("pinterest_app_secret") or "").strip())
    out["pinterest_configured"] = bool((row.get("pinterest_access_token") or "").strip() and (row.get("pinterest_board_id") or "").strip())
    # RSS feed for Pinterest auto-pin: public website URL + /rss.xml (deployed site serves this)
    domain_url = (row.get("domain_url") or "").strip()
    base = domain_url.rstrip("/") if domain_url else ""
    rss_base = (request.url_root or "").rstrip("/")
    out["pinterest_rss_feed_url"] = base + "/rss.xml" if base else rss_base + "/rss/domain/" + str(pk)
    # Multi boards: each board has its own RSS URL
    raw_boards = (row.get("pinterest_boards") or "").strip()
    pinterest_boards = []
    if raw_boards:
        try:
            pinterest_boards = json.loads(raw_boards) if isinstance(raw_boards, str) else raw_boards
            if not isinstance(pinterest_boards, list):
                pinterest_boards = []
        except (json.JSONDecodeError, TypeError):
            pass
    for b in pinterest_boards:
        if isinstance(b, dict) and b.get("slug"):
            # Per-board RSS URL: https://domain/rss/{slug}.xml (static deploy serves rss/<slug>.xml)
            base = (domain_url or "").strip().rstrip("/")
            if base and not base.startswith("http"):
                base = "https://" + base
            b["rss_url"] = (base + "/rss/" + b["slug"] + ".xml") if base else (rss_base + "/rss/domain/" + str(pk) + "/board/" + b["slug"])
    out["pinterest_boards"] = pinterest_boards
    out["pinterest_mode"] = (row.get("pinterest_mode") or "").strip() or None  # 'rss' | 'manual' | 'schedule'
    out["pinterest_domain_verify"] = (row.get("pinterest_domain_verify") or "").strip() or None  # meta content for Pinterest claim
    return jsonify(out)


def _sibling_domain_index(domain_index):
    """Return sibling domain_index in same pair: 0<->1, 2<->3."""
    if domain_index is None:
        return None
    idx = int(domain_index) if domain_index is not None else 0
    if idx in (0, 1):
        return 1 - idx
    if idx in (2, 3):
        return 5 - idx  # 2->3, 3->2
    return None


@app.route("/api/domains/<int:domain_id>/first-article", methods=["GET"])
def api_domain_first_article(domain_id):
    """GET: First article (title + article_content) for this domain for Pin Editor 'Test with first article'.
    Query: sibling_flip=1 to also return sibling domain's images flipped horizontally (A<->B, C<->D)."""
    with get_connection() as conn:
        cur = db_execute(conn, """SELECT d.id, d.domain_url, d.domain_name, d.group_id, d.domain_index
            FROM domains d WHERE d.id = ?""", (domain_id,))
        row = dict_row(cur.fetchone())
        if not row:
            return jsonify({"error": "Domain not found"}), 404
        domain_url = (row.get("domain_url") or "").strip()
        domain_name = (row.get("domain_name") or "").strip()
        domain_display = domain_url or domain_name
        if domain_display and "://" in domain_display:
            try:
                from urllib.parse import urlparse
                domain_display = urlparse(domain_display).hostname or domain_display
            except Exception:
                pass
        cur = db_execute(conn, """SELECT t.id AS title_id, t.title
            FROM titles t WHERE t.domain_id = ? ORDER BY t.id LIMIT 1""", (domain_id,))
        first_title = dict_row(cur.fetchone())
        if not first_title:
            return jsonify({"error": "No titles for this domain", "domain": domain_display, "title": "", "main_image": "", "top_image": "", "bottom_image": ""}), 200
        title_id = first_title["title_id"]
        title_text = (first_title.get("title") or "").strip()
        cur = db_execute(conn, """SELECT main_image, top_image, bottom_image, ingredient_image, recipe_title_pin
            FROM article_content WHERE title_id = ? AND language_code = 'en'""", (title_id,))
        ac = dict_row(cur.fetchone()) or {}
    main_image = (ac.get("main_image") or "").strip()
    top_image = (ac.get("top_image") or "").strip() or main_image
    bottom_image = (ac.get("bottom_image") or "").strip() or (ac.get("ingredient_image") or "").strip() or main_image
    recipe_title_pin = (ac.get("recipe_title_pin") or "").strip() or title_text
    out = {
        "title_id": title_id,
        "title": title_text,
        "domain": domain_display,
        "recipe_title_pin": recipe_title_pin,
        "main_image": main_image,
        "top_image": top_image,
        "bottom_image": bottom_image,
        "ingredient_image": (ac.get("ingredient_image") or "").strip(),
    }
    sibling_flip = str(request.args.get("sibling_flip", "")).strip().lower() in ("1", "true", "yes")
    smain, stop, sbot = "", "", ""
    if sibling_flip and row.get("group_id"):
        sibling_idx = _sibling_domain_index(row.get("domain_index"))
        if sibling_idx is not None:
            with get_connection() as conn:
                cur = db_execute(conn, """SELECT d.id FROM domains d
                    WHERE d.group_id = ? AND d.domain_index = ?""", (row["group_id"], sibling_idx))
                srow = cur.fetchone()
                if srow:
                    sibling_domain_id = dict_row(srow)["id"]
                    cur = db_execute(conn, """SELECT t.id FROM titles t
                        WHERE t.domain_id = ? AND TRIM(t.title) = ? ORDER BY t.id LIMIT 1""",
                        (sibling_domain_id, title_text))
                    stitle = cur.fetchone()
                    if stitle:
                        sibling_title_id = dict_row(stitle)["id"]
                        cur = db_execute(conn, """SELECT main_image, top_image, bottom_image
                            FROM article_content WHERE title_id = ? AND language_code = 'en'""", (sibling_title_id,))
                        sac = dict_row(cur.fetchone()) or {}
                        smain = (sac.get("main_image") or "").strip()
                        stop = (sac.get("top_image") or "").strip() or smain
                        sbot = (sac.get("bottom_image") or "").strip() or smain
        if smain or stop or sbot:
            user_id = None
            try:
                u = get_current_user()
                if u:
                    user_id = u.get("id")
            except Exception:
                pass
            user_config = get_user_config_for_api(user_id) or {}
            try:
                from imagine import flip_image_horizontal_and_upload
                flipped = {}
                prefix = "pin_editor_sibling"
                if smain:
                    flipped["main_image"] = flip_image_horizontal_and_upload(smain, prefix + "_main", user_config)
                if stop:
                    flipped["top_image"] = flip_image_horizontal_and_upload(stop, prefix + "_top", user_config)
                if sbot:
                    flipped["bottom_image"] = flip_image_horizontal_and_upload(sbot, prefix + "_bot", user_config)
                out["sibling_flipped"] = flipped
            except Exception as e:
                out["sibling_flipped_error"] = str(e)
    return jsonify(out)


def _slug_from_board_name(name):
    """Generate URL-safe slug from board name: lowercase, spaces to hyphens, strip non-alphanumeric."""
    if not name or not isinstance(name, str):
        return ""
    s = name.strip().lower()
    s = " ".join(s.split())
    s = "".join(c if c.isalnum() or c in " -" else "" for c in s)
    s = "-".join(s.split()).strip("-")
    return s[:128] if s else "board"


@app.route("/api/domains/<int:pk>/pinterest", methods=["PUT"])
@login_required
def api_domain_pinterest(pk):
    """Set Pinterest mode, domain verify, and/or boards for domain."""
    data = request.get_json(silent=True) or {}
    mode = (data.get("pinterest_mode") or "").strip().lower()
    if mode and mode not in ("rss", "manual", "schedule"):
        return jsonify({"success": False, "error": "pinterest_mode must be rss, manual, or schedule"}), 400
    mode = mode if mode else None
    pinterest_domain_verify = (data.get("pinterest_domain_verify") or "").strip() or None
    if pinterest_domain_verify and len(pinterest_domain_verify) > 128:
        pinterest_domain_verify = pinterest_domain_verify[:128]
    raw_boards = data.get("pinterest_boards")
    pinterest_boards_json = None
    if raw_boards is not None:
        if not isinstance(raw_boards, list):
            return jsonify({"success": False, "error": "pinterest_boards must be an array"}), 400
        seen_slugs = set()
        normalized = []
        for b in raw_boards:
            if not isinstance(b, dict):
                continue
            name = (b.get("name") or "").strip() or "Board"
            slug = (b.get("slug") or "").strip() or _slug_from_board_name(name)
            if not slug:
                slug = _slug_from_board_name(name)
            slug = slug.lower().replace(" ", "-")[:64]
            if slug in seen_slugs:
                continue
            seen_slugs.add(slug)
            normalized.append({"name": name[:200], "slug": slug})
        pinterest_boards_json = json.dumps(normalized)
    with get_connection() as conn:
        cur = db_execute(conn, "SELECT id, pinterest_mode FROM domains WHERE id = ?", (pk,))
        row = cur.fetchone()
        if not row:
            return jsonify({"error": "Domain not found"}), 404
        new_mode = mode if mode is not None else (dict_row(row).get("pinterest_mode") or "")
        if pinterest_boards_json is not None:
            db_execute(conn, "UPDATE domains SET pinterest_mode = ?, pinterest_domain_verify = ?, pinterest_boards = ? WHERE id = ?",
                       (new_mode or "", pinterest_domain_verify or "", pinterest_boards_json, pk))
        else:
            db_execute(conn, "UPDATE domains SET pinterest_mode = ?, pinterest_domain_verify = ? WHERE id = ?", (new_mode or "", pinterest_domain_verify or "", pk))
    return jsonify({"success": True, "pinterest_mode": mode, "pinterest_domain_verify": pinterest_domain_verify})


@app.route("/api/domains/<int:pk>/change-group", methods=["PUT"])
@login_required
def api_domain_change_group(pk):
    """Change the group assignment for a domain."""
    user = get_current_user()
    user_id = user["id"]
    is_admin = user.get("is_admin", 0)
    
    data = request.get_json(silent=True) or {}
    group_id = data.get("group_id")
    if group_id == "":
        group_id = None
    elif group_id:
        group_id = int(group_id)
    
    # Check if user has access to this domain
    user_domain_ids = get_user_domain_ids(user_id, is_admin)
    if not is_admin and pk not in user_domain_ids:
        return jsonify({"success": False, "error": "Access denied"}), 403
    
    # If assigning to a group, check if user has access to that group
    if group_id and not is_admin:
        user_group_ids = get_user_group_ids(user_id, is_admin)
        if group_id not in user_group_ids:
            return jsonify({"success": False, "error": "You don't have access to this group"}), 403
    
    with get_connection() as conn:
        # Get next domain_index in the group
        domain_index = None
        if group_id:
            cur = db_execute(conn, "SELECT COALESCE(MAX(domain_index), -1) + 1 as next_idx FROM domains WHERE group_id = ?", (group_id,))
            row = dict_row(cur.fetchone())
            domain_index = row.get("next_idx") if row else 0
        
        db_execute(conn, "UPDATE domains SET group_id = ?, domain_index = ? WHERE id = ?", (group_id, domain_index, pk))
    
    return jsonify({"success": True})


@app.route("/api/domains/<int:pk>/delete", methods=["POST", "DELETE"])
@login_required
def api_domain_delete(pk):
    """Delete a single domain and its content. Returns JSON (no redirect)."""
    user = get_current_user()
    user_id = user["id"]
    is_admin = user.get("is_admin", 0)
    user_domain_ids = get_user_domain_ids(user_id, is_admin)
    if not is_admin and pk not in user_domain_ids:
        return jsonify({"success": False, "error": "Access denied"}), 403

    with get_connection() as conn:
        cur = db_execute(conn, "SELECT id FROM titles WHERE domain_id = ?", (pk,))
        title_ids = [dict_row(r)["id"] for r in cur.fetchall()]
        if title_ids:
            ph = ",".join(["?"] * len(title_ids))
            db_execute(conn, f"DELETE FROM article_content WHERE title_id IN ({ph})", tuple(title_ids))
            db_execute(conn, f"DELETE FROM titles WHERE id IN ({ph})", tuple(title_ids))
        db_execute(conn, "DELETE FROM domain_template_assignments WHERE domain_id = ?", (pk,))
        db_execute(conn, "DELETE FROM domain_templates WHERE domain_id = ?", (pk,))
        db_execute(conn, "DELETE FROM user_domains WHERE domain_id = ?", (pk,))
        cur = db_execute(conn, "DELETE FROM domains WHERE id = ?", (pk,))
        if cur.rowcount == 0:
            return jsonify({"success": False, "error": "Domain not found"}), 404
    return jsonify({"success": True})


