def _parse_multi_action_id_list(val):
    """Parse JSON list or comma/space-separated string into sorted unique positive ints."""
    if val is None:
        return []
    if isinstance(val, str):
        parts = val.replace(",", " ").split()
        out = []
        for p in parts:
            p = p.strip()
            if p.isdigit():
                out.append(int(p))
        return sorted(set(out))
    if isinstance(val, list):
        out = []
        for x in val:
            try:
                s = str(x).strip()
                if s.isdigit():
                    out.append(int(s))
            except (TypeError, ValueError):
                pass
        return sorted(set(out))
    return []


def _parse_domain_id_sequence_preserving_order(item):
    """Parse a JSON list of domain ids; preserve order; require unique positive ints within the batch."""
    if not isinstance(item, list):
        return None
    out = []
    seen = set()
    for x in item:
        try:
            n = int(x)
            if n <= 0:
                return None
            if n in seen:
                return None
            seen.add(n)
            out.append(n)
        except (TypeError, ValueError):
            return None
    return out if out else None


def _normalize_multi_batch_domain_groups(raw):
    """Parse batch_domain_groups JSON: list of domain-id lists. Returns list only if 2+ batches (multi-move)."""
    if raw is None or not isinstance(raw, list) or len(raw) < 2:
        return None
    out = []
    for item in raw:
        ids = _parse_domain_id_sequence_preserving_order(item)
        if not ids:
            return None
        if len(ids) > 4:
            return None
        out.append(ids)
    if len(out) < 2:
        return None
    flat = [x for g in out for x in g]
    if len(flat) != len(set(flat)):
        return None
    return out


@app.route("/api/domains/multi-group-action", methods=["POST"])
@login_required
def api_domains_multi_group_action():
    """Apply action to groups, specific domains, or specific titles.
    Body: { action, group_ids?: [], domain_ids?: [], title_ids?: [], target_group_id?: int, batch_domain_groups?: [][] }
    Exactly one targeting mode: non-empty group_ids, domain_ids, or title_ids.
    For action move_to_group: target_group_id required; group or domain scope only; blocked if bulk/deploy busy.
    Multi-batch move: send batch_domain_groups as 2+ lists of domain IDs (same IDs as domain_ids, each batch ≤4);
    each batch becomes a new subgroup under target_group_id. Single-batch move merges into target (max 4 domains there).
    """
    user = get_current_user()
    user_id = user["id"]
    is_admin = user.get("is_admin", 0)
    data = request.get_json(silent=True) or {}
    action = (data.get("action") or "").strip().lower()
    if action not in (
        "ungroup",
        "clear_articles",
        "delete_titles",
        "delete_domains",
        "clear_images",
        "clear_content",
        "clear_pins",
        "move_to_group",
        "archive_group",
        "unarchive_group",
    ):
        return jsonify({"success": False, "error": "Invalid action"}), 400

    group_ids = _parse_multi_action_id_list(data.get("group_ids"))
    domain_ids = _parse_multi_action_id_list(data.get("domain_ids"))
    title_ids = _parse_multi_action_id_list(data.get("title_ids"))

    modes = sum(1 for x in (group_ids, domain_ids, title_ids) if x)
    if modes != 1:
        return jsonify({"success": False, "error": "Send exactly one of: group_ids, domain_ids, or title_ids"}), 400

    user_domain_ids = get_user_domain_ids(user_id, is_admin)
    user_group_ids = get_user_group_ids(user_id, is_admin) if not is_admin else None

    def get_all_descendants(conn, gid):
        result = [gid]
        cur = db_execute(conn, "SELECT id FROM `groups` WHERE parent_group_id = ?", (gid,))
        children = [dict_row(r)["id"] for r in cur.fetchall()]
        for c in children:
            result.extend(get_all_descendants(conn, c))
        return result

    def scope_label():
        if title_ids:
            return f"{len(title_ids)} title(s)"
        if domain_ids:
            return f"{len(domain_ids)} domain(s)"
        return f"{len(group_ids)} group(s)"

    with get_connection() as conn:
        target_domain_ids = []
        target_title_ids = []

        if title_ids:
            if action in ("ungroup", "delete_domains", "move_to_group", "archive_group", "unarchive_group"):
                return jsonify(
                    {
                        "success": False,
                        "error": "That action uses domain or group scope only—not title IDs.",
                    }
                ), 400
            t_ph = ",".join(["?"] * len(title_ids))
            cur = db_execute(conn, f"SELECT id, domain_id FROM titles WHERE id IN ({t_ph})", tuple(title_ids))
            rows = [dict_row(r) for r in cur.fetchall()]
            found = {r["id"] for r in rows}
            missing = [t for t in title_ids if t not in found]
            if missing:
                return jsonify({"success": False, "error": f"Unknown title_id(s): {missing[:10]}"}), 400
            if not is_admin:
                for r in rows:
                    if r.get("domain_id") not in (user_domain_ids or []):
                        return jsonify({"success": False, "error": "Access denied to one or more titles"}), 403
            target_title_ids = list(title_ids)

        elif domain_ids:
            d_ph = ",".join(["?"] * len(domain_ids))
            cur = db_execute(conn, f"SELECT id FROM domains WHERE id IN ({d_ph})", tuple(domain_ids))
            found = {dict_row(r)["id"] for r in cur.fetchall()}
            missing = [d for d in domain_ids if d not in found]
            if missing:
                return jsonify({"success": False, "error": f"Unknown domain_id(s): {missing[:10]}"}), 400
            if not is_admin:
                for did in domain_ids:
                    if did not in (user_domain_ids or []):
                        return jsonify({"success": False, "error": "Access denied to one or more domains"}), 403
            if action in ("archive_group", "unarchive_group"):
                return jsonify({"success": False, "error": "Archive / unarchive uses group selection only—not domain IDs."}), 400
            target_domain_ids = list(domain_ids)

        else:
            if not is_admin:
                bad = [g for g in group_ids if g not in user_group_ids]
                if bad:
                    return jsonify({"success": False, "error": "Access denied to some groups"}), 403
            all_gids = []
            for gid in group_ids:
                all_gids.extend(get_all_descendants(conn, gid))
            all_gids = list(set(all_gids))
            if not all_gids:
                return jsonify({"success": True, "count": 0, "message": "No groups"})
            ph = ",".join(["?"] * len(all_gids))
            if action == "ungroup":
                if is_admin:
                    cur = db_execute(conn, f"UPDATE domains SET group_id = NULL, domain_index = NULL WHERE group_id IN ({ph})", tuple(all_gids))
                else:
                    if not user_domain_ids:
                        return jsonify({"success": True, "count": 0})
                    ud_ph = ",".join(["?"] * len(user_domain_ids))
                    cur = db_execute(conn, f"UPDATE domains SET group_id = NULL, domain_index = NULL WHERE group_id IN ({ph}) AND id IN ({ud_ph})", tuple(all_gids) + tuple(user_domain_ids))
                count = cur.rowcount if hasattr(cur, "rowcount") else 0
                return jsonify({"success": True, "count": count, "message": f"Unassigned {count} domain(s) from {len(group_ids)} group(s)"})

            if action == "archive_group":
                for ag in all_gids:
                    db_execute(conn, "UPDATE `groups` SET archived = 1 WHERE id = ?", (ag,))
                log.info("[multi-group] archive_group user=%s roots=%s rows=%s", user_id, group_ids, len(all_gids))
                return jsonify(
                    {
                        "success": True,
                        "count": len(all_gids),
                        "message": f"Archived {len(group_ids)} selected tree(s) ({len(all_gids)} group row(s)). They no longer appear on Domains home; open by URL or unarchive to restore.",
                    }
                )

            if action == "unarchive_group":
                for ag in all_gids:
                    db_execute(conn, "UPDATE `groups` SET archived = 0 WHERE id = ?", (ag,))
                log.info("[multi-group] unarchive_group user=%s roots=%s rows=%s", user_id, group_ids, len(all_gids))
                return jsonify(
                    {
                        "success": True,
                        "count": len(all_gids),
                        "message": f"Restored {len(group_ids)} tree(s) ({len(all_gids)} group row(s)) to the active list.",
                    }
                )

            cur = db_execute(conn, f"SELECT id FROM domains WHERE group_id IN ({ph})", tuple(all_gids))
            target_domain_ids = [dict_row(r)["id"] for r in cur.fetchall()]
            if not target_domain_ids:
                return jsonify({"success": True, "count": 0, "message": "No domains in selected groups"})

        dom_ph = ",".join(["?"] * len(target_domain_ids)) if target_domain_ids else ""

        def titles_for_domains():
            if not target_domain_ids:
                return []
            cur2 = db_execute(conn, f"SELECT id FROM titles WHERE domain_id IN ({dom_ph})", tuple(target_domain_ids))
            return [dict_row(r)["id"] for r in cur2.fetchall()]

        effective_title_ids = target_title_ids if target_title_ids else titles_for_domains()

        if action == "ungroup":
            if not target_domain_ids:
                return jsonify({"success": False, "error": "No domains to ungroup"}), 400
            if is_admin:
                cur = db_execute(conn, f"UPDATE domains SET group_id = NULL, domain_index = NULL WHERE id IN ({dom_ph})", tuple(target_domain_ids))
            else:
                allowed = [d for d in target_domain_ids if d in user_domain_ids]
                if not allowed:
                    return jsonify({"success": True, "count": 0})
                aph = ",".join(["?"] * len(allowed))
                cur = db_execute(conn, f"UPDATE domains SET group_id = NULL, domain_index = NULL WHERE id IN ({aph})", tuple(allowed))
            count = cur.rowcount if hasattr(cur, "rowcount") else 0
            return jsonify({"success": True, "count": count, "message": f"Unassigned {count} domain(s) ({scope_label()})"})

        if action == "move_to_group":
            try:
                target_group_id = int(data.get("target_group_id"))
            except (TypeError, ValueError):
                return jsonify({"success": False, "error": "target_group_id required (integer group id)"}), 400
            if target_group_id <= 0:
                return jsonify({"success": False, "error": "Invalid target_group_id"}), 400
            if not target_domain_ids:
                return jsonify({"success": False, "error": "No domains to move"}), 400
            cur = db_execute(conn, "SELECT id FROM `groups` WHERE id = ?", (target_group_id,))
            if not cur.fetchone():
                return jsonify({"success": False, "error": "Target group not found"}), 404
            if not is_admin and target_group_id not in (user_group_ids or []):
                return jsonify({"success": False, "error": "You do not have access to the target group"}), 403
            if not is_admin:
                for did in target_domain_ids:
                    if did not in (user_domain_ids or []):
                        return jsonify({"success": False, "error": "Access denied to one or more domains"}), 403
            move_set = set(int(x) for x in target_domain_ids)
            busy = _bulk_work_conflicts_domain_ids(conn, move_set)
            if busy:
                return jsonify({"success": False, "error": busy}), 409

            batch_groups = _normalize_multi_batch_domain_groups(data.get("batch_domain_groups"))
            if batch_groups:
                flat_from_batches = sorted(x for g in batch_groups for x in g)
                flat_from_body = sorted(int(x) for x in target_domain_ids)
                if flat_from_batches != flat_from_body:
                    return jsonify(
                        {
                            "success": False,
                            "error": "batch_domain_groups must list the same domain IDs as domain_ids (each id once).",
                        }
                    ), 400

                def _unique_child_group_name(parent_id, base_name):
                    base = (base_name or "Batch").strip() or "Batch"
                    cur_n = db_execute(conn, "SELECT name FROM `groups` WHERE parent_group_id = ?", (parent_id,))
                    existing = {dict_row(r)["name"] for r in cur_n.fetchall()}
                    name = base
                    n = 1
                    while name in existing:
                        n += 1
                        name = f"{base} ({n})"
                    return name

                created_ids = []
                total_moved = 0
                for idx, batch in enumerate(batch_groups):
                    cur_src = db_execute(
                        conn,
                        "SELECT g.name FROM domains d JOIN `groups` g ON g.id = d.group_id WHERE d.id = ?",
                        (batch[0],),
                    )
                    row_src = dict_row(cur_src.fetchone())
                    src_name = (row_src.get("name") if row_src else None) or f"Batch {idx + 1}"
                    child_name = _unique_child_group_name(target_group_id, src_name)
                    cur_ins = db_execute(
                        conn,
                        "INSERT INTO `groups` (name, parent_group_id) VALUES (?, ?)",
                        (child_name, target_group_id),
                    )
                    new_gid = last_insert_id(cur_ins)
                    if not new_gid:
                        fb = db_execute(
                            conn,
                            "SELECT id FROM `groups` WHERE name = ? AND parent_group_id = ? ORDER BY id DESC LIMIT 1",
                            (child_name, target_group_id),
                        )
                        rfb = dict_row(fb.fetchone())
                        new_gid = rfb.get("id") if rfb else None
                    if not new_gid:
                        return jsonify({"success": False, "error": "Could not create subgroup for multi-batch move"}), 500
                    try:
                        db_execute(conn, "INSERT INTO user_groups (user_id, group_id) VALUES (?, ?)", (user_id, new_gid))
                    except Exception:
                        pass
                    b_ph = ",".join(["?"] * len(batch))
                    for did in batch:
                        db_execute(conn, "UPDATE domains SET group_id = ? WHERE id = ?", (new_gid, did))
                    db_execute(
                        conn,
                        f"UPDATE titles SET group_id = ? WHERE domain_id IN ({b_ph})",
                        (new_gid,) + tuple(batch),
                    )
                    for i, did in enumerate(batch):
                        db_execute(conn, "UPDATE domains SET domain_index = ? WHERE id = ?", (i, did))
                    created_ids.append(new_gid)
                    total_moved += len(batch)

                log.info(
                    "[multi-group] move_to_group multi_batch user=%s batches=%s domains=%s parent=%s new_groups=%s",
                    user_id,
                    len(batch_groups),
                    total_moved,
                    target_group_id,
                    created_ids,
                )
                return jsonify(
                    {
                        "success": True,
                        "count": total_moved,
                        "new_group_ids": created_ids,
                        "message": (
                            f"Moved {len(batch_groups)} batches ({total_moved} domain(s)) under group {target_group_id}: "
                            f"created subgroups {created_ids}. Open that parent to see them."
                        ),
                    }
                )

            cur = db_execute(conn, "SELECT id FROM domains WHERE group_id = ?", (target_group_id,))
            existing_in_target = {dict_row(r)["id"] for r in cur.fetchall()}
            other = existing_in_target - move_set
            if len(other) + len(move_set) > 4:
                return jsonify(
                    {
                        "success": False,
                        "error": (
                            f"Target group would have more than 4 domains (A–D). "
                            f"It already has {len(other)} other domain(s); you are moving {len(move_set)}."
                        ),
                    }
                ), 400
            for did in target_domain_ids:
                db_execute(conn, "UPDATE domains SET group_id = ? WHERE id = ?", (target_group_id, did))
            # titles.group_id must follow the domain: bulk/group queries use COALESCE(t.group_id, d.group_id).
            # If only domains moved, old title.group_id kept rows tied to the previous group for "Run group" counts and processing.
            db_execute(
                conn,
                f"UPDATE titles SET group_id = ? WHERE domain_id IN ({dom_ph})",
                (target_group_id,) + tuple(target_domain_ids),
            )
            cur = db_execute(
                conn,
                "SELECT id FROM domains WHERE group_id = ? ORDER BY COALESCE(domain_index, 999999), id",
                (target_group_id,),
            )
            renum = [dict_row(r)["id"] for r in cur.fetchall()]
            for i, did in enumerate(renum):
                db_execute(conn, "UPDATE domains SET domain_index = ? WHERE id = ?", (i, did))
            log.info(
                "[multi-group] move_to_group user=%s count=%s -> group_id=%s (%s)",
                user_id,
                len(target_domain_ids),
                target_group_id,
                scope_label(),
            )
            return jsonify(
                {
                    "success": True,
                    "count": len(target_domain_ids),
                    "message": f"Moved {len(target_domain_ids)} domain(s) to group {target_group_id}. Domain order renumbered 0–{len(renum) - 1} in that group.",
                }
            )

        if action == "clear_articles":
            if not effective_title_ids:
                return jsonify({"success": True, "count": 0, "message": "No titles"})
            et_ph = ",".join(["?"] * len(effective_title_ids))
            db_execute(conn, f"DELETE FROM article_content WHERE title_id IN ({et_ph})", tuple(effective_title_ids))
            return jsonify({"success": True, "count": len(effective_title_ids), "message": f"Cleared articles for {len(effective_title_ids)} title(s) ({scope_label()})"})

        if action == "clear_images":
            if not effective_title_ids:
                return jsonify({"success": True, "count": 0, "message": "No titles"})
            et_ph = ",".join(["?"] * len(effective_title_ids))
            cur = db_execute(
                conn,
                f"SELECT ac.id FROM article_content ac WHERE ac.title_id IN ({et_ph}) AND ac.language_code = 'en'",
                tuple(effective_title_ids),
            )
            ac_ids = [dict_row(r)["id"] for r in cur.fetchall()]
            if not ac_ids:
                return jsonify({"success": True, "count": 0, "message": "No article_content rows"})
            ac_ph = ",".join(["?"] * len(ac_ids))
            cur = db_execute(conn, f"UPDATE article_content SET main_image = NULL, ingredient_image = NULL, top_image = NULL, bottom_image = NULL WHERE id IN ({ac_ph})", tuple(ac_ids))
            count = cur.rowcount if hasattr(cur, "rowcount") else len(ac_ids)
            return jsonify({"success": True, "count": count, "message": f"Cleared main+ingredient images for {count} article row(s) ({scope_label()})"})

        if action == "clear_content":
            if not effective_title_ids:
                return jsonify({"success": True, "count": 0, "message": "No titles"})
            et_ph = ",".join(["?"] * len(effective_title_ids))
            cur = db_execute(
                conn,
                f"SELECT ac.id FROM article_content ac WHERE ac.title_id IN ({et_ph}) AND ac.language_code = 'en'",
                tuple(effective_title_ids),
            )
            ac_ids = [dict_row(r)["id"] for r in cur.fetchall()]
            if not ac_ids:
                return jsonify({"success": True, "count": 0, "message": "No article_content rows"})
            ac_ph = ",".join(["?"] * len(ac_ids))
            cur = db_execute(conn, f"UPDATE article_content SET article_html = NULL, article_css = NULL WHERE id IN ({ac_ph})", tuple(ac_ids))
            count = cur.rowcount if hasattr(cur, "rowcount") else len(ac_ids)
            return jsonify({"success": True, "count": count, "message": f"Cleared HTML+CSS for {count} article row(s) ({scope_label()})"})

        if action == "clear_pins":
            if not effective_title_ids:
                return jsonify({"success": True, "count": 0, "message": "No titles"})
            et_ph = ",".join(["?"] * len(effective_title_ids))
            cur = db_execute(
                conn,
                f"SELECT ac.id FROM article_content ac WHERE ac.title_id IN ({et_ph}) AND ac.language_code = 'en'",
                tuple(effective_title_ids),
            )
            ac_ids = [dict_row(r)["id"] for r in cur.fetchall()]
            if not ac_ids:
                return jsonify({"success": True, "count": 0, "message": "No article_content rows"})
            ac_ph = ",".join(["?"] * len(ac_ids))
            cur = db_execute(conn, f"UPDATE article_content SET pin_image = NULL WHERE id IN ({ac_ph})", tuple(ac_ids))
            count = cur.rowcount if hasattr(cur, "rowcount") else len(ac_ids)
            return jsonify({"success": True, "count": count, "message": f"Cleared pin images for {count} article row(s) ({scope_label()})"})

        if action == "delete_titles":
            if not effective_title_ids:
                return jsonify({"success": True, "count": 0, "message": "No titles"})
            et_ph = ",".join(["?"] * len(effective_title_ids))
            db_execute(conn, f"DELETE FROM article_content WHERE title_id IN ({et_ph})", tuple(effective_title_ids))
            db_execute(conn, f"DELETE FROM titles WHERE id IN ({et_ph})", tuple(effective_title_ids))
            return jsonify({"success": True, "count": len(effective_title_ids), "message": f"Deleted {len(effective_title_ids)} title(s) ({scope_label()})"})

        if action == "delete_domains":
            if not target_domain_ids:
                return jsonify({"success": False, "error": "Delete Domains requires domain or group scope, not title IDs only"}), 400
            cur = db_execute(conn, f"SELECT id FROM titles WHERE domain_id IN ({dom_ph})", tuple(target_domain_ids))
            all_tids = [dict_row(r)["id"] for r in cur.fetchall()]
            if all_tids:
                t_ph2 = ",".join(["?"] * len(all_tids))
                db_execute(conn, f"DELETE FROM article_content WHERE title_id IN ({t_ph2})", tuple(all_tids))
                db_execute(conn, f"DELETE FROM titles WHERE id IN ({t_ph2})", tuple(all_tids))
            db_execute(conn, f"DELETE FROM domain_template_assignments WHERE domain_id IN ({dom_ph})", tuple(target_domain_ids))
            db_execute(conn, f"DELETE FROM domain_templates WHERE domain_id IN ({dom_ph})", tuple(target_domain_ids))
            db_execute(conn, f"DELETE FROM user_domains WHERE domain_id IN ({dom_ph})", tuple(target_domain_ids))
            db_execute(conn, f"DELETE FROM domains WHERE id IN ({dom_ph})", tuple(target_domain_ids))
            return jsonify({"success": True, "count": len(target_domain_ids), "message": f"Deleted {len(target_domain_ids)} domain(s) ({scope_label()})"})

    return jsonify({"success": False, "error": "Unknown action"}), 400


@app.route("/api/domains/clear-group/<int:group_id>", methods=["POST"])
@login_required
def api_domains_clear_group(group_id):
    """Remove all domains from a specific group."""
    user = get_current_user()
    user_id = user["id"]
    is_admin = user.get("is_admin", 0)
    
    # Check if user has access to this group
    if not is_admin:
        user_group_ids = get_user_group_ids(user_id, is_admin)
        if group_id not in user_group_ids:
            return jsonify({"success": False, "error": "Access denied to this group"}), 403
    
    # Get user's accessible domains
    user_domain_ids = get_user_domain_ids(user_id, is_admin)
    
    with get_connection() as conn:
        if is_admin:
            # Admin: clear all domains in this group
            cur = db_execute(conn, "UPDATE domains SET group_id = NULL, domain_index = NULL WHERE group_id = ?", (group_id,))
            count = cur.rowcount
        elif user_domain_ids:
            # Regular user: clear only their domains in this group
            placeholders = ",".join(["?"] * len(user_domain_ids))
            cur = db_execute(conn, f"UPDATE domains SET group_id = NULL, domain_index = NULL WHERE group_id = ? AND id IN ({placeholders})", (group_id,) + tuple(user_domain_ids))
            count = cur.rowcount
        else:
            count = 0
    
    return jsonify({"success": True, "count": count})

@app.route("/api/domains/<int:pk>/categories", methods=["GET", "PUT"])
def api_domain_categories(pk):
    """GET: Return categories_list for domain. PUT: Update categories_list (body: {"categories": [...]})."""
    with get_connection() as conn:
        cur = db_execute(conn, "SELECT id, categories_list FROM domains WHERE id = ?", (pk,))
        row = dict_row(cur.fetchone())
    if not row:
        return jsonify({"error": "Domain not found"}), 404
    if request.method == "PUT":
        data = request.get_json(silent=True) or {}
        raw = data.get("categories")
        if raw is None:
            return jsonify({"success": False, "error": "categories is required"}), 400
        # Accept list of strings or list of {id, categorie}
        out = []
        if isinstance(raw, list):
            for i, item in enumerate(raw):
                if isinstance(item, dict):
                    name = (item.get("categorie") or item.get("name") or item.get("category") or "").strip()
                    out.append({"id": int(item.get("id", i + 1)), "categorie": name or "Other"})
                else:
                    out.append({"id": i + 1, "categorie": (str(item) or "").strip() or "Other"})
        categories_json = json.dumps(out) if out else None
        with get_connection() as conn:
            db_execute(conn, "UPDATE domains SET categories_list = ? WHERE id = ?", (categories_json, pk))
        return jsonify({"success": True, "id": pk, "categories": out})
    raw = (row.get("categories_list") or "").strip()
    categories = []
    if raw:
        try:
            categories = json.loads(raw)
            if not isinstance(categories, list):
                categories = []
        except Exception:
            pass
    return jsonify({"id": pk, "categories": categories})


def _hex_to_rgb(hex_str):
    """Convert #RRGGBB or #RGB to (r,g,b) tuple."""
    h = (hex_str or "").strip().lstrip("#")
    if len(h) == 3:
        h = "".join(c * 2 for c in h)
    if len(h) != 6:
        return None
    try:
        return (int(h[0:2], 16), int(h[2:4], 16), int(h[4:6], 16))
    except ValueError:
        return None


def _replace_color_in_text(old_hex, new_hex, text):
    """Replace old_hex (as #hex or rgb(r,g,b)) with new_hex in text."""
    if not text or not old_hex or not new_hex:
        return text
    if not re.match(r"^#[0-9a-fA-F]{3,6}$", (old_hex or "").strip()):
        return text
    if not re.match(r"^#[0-9a-fA-F]{3,6}$", (new_hex or "").strip()):
        return text
    old_hex = old_hex.strip()
    new_hex = new_hex.strip()
    out = re.sub(re.escape(old_hex), new_hex, text, flags=re.IGNORECASE)
    rgb = _hex_to_rgb(old_hex)
    if rgb:
        for pattern in [f"rgb({rgb[0]},{rgb[1]},{rgb[2]})", f"rgb({rgb[0]}, {rgb[1]}, {rgb[2]})"]:
            out = out.replace(pattern, new_hex)
    return out


def _update_visual_customizations_colors(conn, domain_id, old_colors, new_colors):
    """Replace old color values with new in visual_customizations for domain."""
    cur = db_execute(conn, "SELECT visual_customizations FROM domains WHERE id = ?", (domain_id,))
    row = cur.fetchone()
    if not row:
        return False
    raw = (dict_row(row).get("visual_customizations") or "").strip()
    if not raw:
        return False
    try:
        customizations = json.loads(raw) if isinstance(raw, str) else raw
    except (json.JSONDecodeError, TypeError):
        return False
    if not isinstance(customizations, list):
        return False
    changed = False
    for c in customizations:
        for key in ("styles", "insert_after"):
            val = c.get(key)
            if not isinstance(val, str):
                continue
            new_val = val
            for k, new_color in new_colors.items():
                old_color = old_colors.get(k)
                if old_color and old_color != new_color:
                    new_val = _replace_color_in_text(old_color, new_color, new_val)
            if new_val != val:
                c[key] = new_val
                changed = True
    if changed:
        db_execute(conn, "UPDATE domains SET visual_customizations = ? WHERE id = ?", (json.dumps(customizations), domain_id))
    return changed


def _update_article_colors(conn, title_id, domain_colors, old_colors=None):
    """Update article CSS with new domain colors. Generators use both :root vars and direct hex
    (e.g. color: #6C8AE4). We replace ALL occurrences of each old hex with the new value.
    old_colors: previous domain_colors from DB (used when generators output direct hex, no :root)."""
    import re
    old_colors = old_colors or {}
    cur = db_execute(conn, "SELECT article_css FROM article_content WHERE title_id = ? AND language_code = 'en'", (title_id,))
    row = cur.fetchone()
    if not row:
        return
    css = (dict_row(row).get("article_css") or "").strip()
    if not css:
        return
    
    # Map of CSS variable names to domain color keys
    color_map = {
        "--primary": "primary", "--secondary": "secondary", "--accent": "primary",
        "--background": "background", "--container-bg": "background",
        "--text-primary": "text_primary", "--text-secondary": "text_secondary",
        "--border": "border", "--button-print": "primary", "--button-pin": "button_pin",
        "--link": "primary", "--list-marker": "primary"
    }
    
    # Build old_hex -> (color_key, new_color) for replacement. Use placeholders to avoid collisions.
    placeholder_prefix = "__DOMAIN_COLOR_"
    replacements = []  # (old_hex, placeholder or new_color)
    
    # Source 1: old_colors from DB (works for direct hex in generators 2,4,6,7,8,9)
    for color_key, new_color in domain_colors.items():
        old_hex = old_colors.get(color_key)
        if old_hex and old_hex != new_color and re.match(r'^#[0-9a-fA-F]{3,6}$', old_hex):
            placeholder = placeholder_prefix + color_key.upper() + "__"
            replacements.append((old_hex, placeholder))
    
    # Source 2: extract from :root (for generators that use CSS variables)
    for css_var, color_key in color_map.items():
        if color_key not in domain_colors:
            continue
        new_color = domain_colors[color_key]
        for hex_pat in (r'#[0-9a-fA-F]{6}', r'#[0-9a-fA-F]{3}'):
            for m in re.finditer(rf'{re.escape(css_var)}\s*:\s*({hex_pat})\s*[;)]', css):
                old_hex = m.group(1)
                if old_hex != new_color and not any(r[0] == old_hex for r in replacements):
                    placeholder = placeholder_prefix + color_key.upper() + "__"
                    replacements.append((old_hex, placeholder))
    
    # Apply: replace old hex with placeholder (case-insensitive; CSS hex is case-insensitive)
    for old_hex, placeholder in replacements:
        css = re.sub(re.escape(old_hex), placeholder, css, flags=re.IGNORECASE)
    
    # Replace placeholders with new colors
    for color_key, new_color in domain_colors.items():
        placeholder = placeholder_prefix + color_key.upper() + "__"
        css = css.replace(placeholder, new_color)
    
    db_execute(conn, "UPDATE article_content SET article_css = ? WHERE title_id = ? AND language_code = 'en'", (css, title_id))


def _regenerate_domain_site_parts(domain_id, domain_colors):
    """Regenerate header, footer, sidebar, category templates with new colors to cache them."""
    # This ensures headers/footers are regenerated with new colors
    # Since they're generated on-the-fly, we just need to ensure the domain_colors are in the DB
    # The next request will automatically use the new colors from _get_domain_website_context
    # We can optionally pre-generate and warm the cache by making a test request
    try:
        base = (WEBSITE_PARTS_API_URL or "").rstrip("/")
        if not base:
            return 0
        
        with get_connection() as conn:
            cur = db_execute(conn, """SELECT header_template, footer_template, side_article_template, 
                category_page_template, writer_template, index_template, article_template_config, domain_fonts, categories_list FROM domains WHERE id = ?""", (domain_id,))
            row = dict_row(cur.fetchone())
            if not row:
                return 0
        
        # Build config with new colors and domain fonts
        config = {"colors": domain_colors, "domain_name": "Preview"}
        cfg_raw = (row.get("article_template_config") or "").strip()
        if cfg_raw:
            try:
                cfg = json.loads(cfg_raw) if isinstance(cfg_raw, str) else cfg_raw
                if isinstance(cfg, dict):
                    config.update(cfg)
                    config["colors"] = domain_colors  # Override with new colors
            except json.JSONDecodeError:
                pass
        df_raw = (row.get("domain_fonts") or "").strip()
        if df_raw:
            try:
                config["fonts"] = _domain_fonts_to_config(df_raw)
            except Exception:
                pass
        
        parts_regenerated = 0
        # Regenerate header
        h_tpl = (row.get("header_template") or "").strip()
        if h_tpl:
            try:
                _fetch_site_part_internal("header", h_tpl, config)
                parts_regenerated += 1
            except Exception:
                pass
        
        # Regenerate footer
        f_tpl = (row.get("footer_template") or "").strip()
        if f_tpl:
            try:
                _fetch_site_part_internal("footer", f_tpl, config)
                parts_regenerated += 1
            except Exception:
                pass
        
        # Regenerate sidebar
        s_tpl = (row.get("side_article_template") or "").strip()
        if s_tpl:
            try:
                _fetch_site_part_internal("sidebar", s_tpl, config)
                parts_regenerated += 1
            except Exception:
                pass
        
        # Regenerate category
        c_tpl = (row.get("category_page_template") or "").strip()
        if c_tpl:
            try:
                config["category_name"] = "Recipes"
                config["articles"] = []
                _fetch_site_part_internal("category", c_tpl, config)
                parts_regenerated += 1
            except Exception:
                pass
        
        # Regenerate writer template
        w_tpl = (row.get("writer_template") or "").strip()
        if w_tpl:
            try:
                config["writer"] = {"name": "Sample Writer", "title": "Food Blogger", "bio": "Sample bio", "avatar": ""}
                _fetch_site_part_internal("writer", w_tpl, config)
                parts_regenerated += 1
            except Exception:
                pass
        
        # Regenerate index template
        idx_tpl = (row.get("index_template") or "").strip()
        if idx_tpl:
            try:
                config["articles"] = []
                config["categories"] = []
                _fetch_site_part_internal("index", idx_tpl, config)
                parts_regenerated += 1
            except Exception:
                pass
        
        return parts_regenerated
    except Exception:
        return 0


@app.route("/api/domains/<int:pk>/articles-by-stat", methods=["GET"])
def api_domain_articles_by_stat(pk):
    """Return articles filtered by stat type (html_css, no_html_css, main_img, no_main_img, ing_img, no_ing_img)."""
    stat_type = request.args.get("type", "")
    if not stat_type:
        return jsonify({"error": "type parameter required"}), 400
    
    with get_connection() as conn:
        sel = "t.id, t.title, ac.main_image, ac.ingredient_image, ac.pin_image, ac.prompt, ac.prompt_image_ingredients, ac.article_html, ac.article_css"
        if stat_type == "prompt":
            cur = db_execute(conn, f"""SELECT {sel} FROM titles t
                JOIN article_content ac ON ac.title_id = t.id AND ac.language_code = 'en'
                WHERE t.domain_id = ? AND TRIM(COALESCE(ac.prompt,'')) != '' AND TRIM(COALESCE(ac.prompt_image_ingredients,'')) != ''
                ORDER BY t.id""", (pk,))
        elif stat_type == "no_prompt":
            cur = db_execute(conn, f"""SELECT {sel} FROM titles t
                LEFT JOIN article_content ac ON ac.title_id = t.id AND ac.language_code = 'en'
                WHERE t.domain_id = ? AND (ac.id IS NULL OR TRIM(COALESCE(ac.prompt,'')) = '' OR TRIM(COALESCE(ac.prompt_image_ingredients,'')) = '')
                ORDER BY t.id""", (pk,))
        elif stat_type == "html_css":
            cur = db_execute(conn, f"""SELECT {sel} FROM titles t
                JOIN article_content ac ON ac.title_id = t.id AND ac.language_code = 'en'
                WHERE t.domain_id = ? AND TRIM(COALESCE(ac.article_html,'')) != '' AND TRIM(COALESCE(ac.article_css,'')) != ''
                ORDER BY t.id""", (pk,))
        elif stat_type == "no_html_css":
            cur = db_execute(conn, f"""SELECT {sel} FROM titles t
                LEFT JOIN article_content ac ON ac.title_id = t.id AND ac.language_code = 'en'
                WHERE t.domain_id = ? AND (ac.id IS NULL OR TRIM(COALESCE(ac.article_html,'')) = '' OR TRIM(COALESCE(ac.article_css,'')) = '')
                ORDER BY t.id""", (pk,))
        elif stat_type == "main_img":
            cur = db_execute(conn, f"""SELECT {sel} FROM titles t
                JOIN article_content ac ON ac.title_id = t.id AND ac.language_code = 'en'
                WHERE t.domain_id = ? AND ac.main_image IS NOT NULL AND TRIM(ac.main_image) LIKE 'http%%'
                ORDER BY t.id""", (pk,))
        elif stat_type == "no_main_img":
            cur = db_execute(conn, f"""SELECT {sel} FROM titles t
                LEFT JOIN article_content ac ON ac.title_id = t.id AND ac.language_code = 'en'
                WHERE t.domain_id = ? AND (ac.main_image IS NULL OR TRIM(COALESCE(ac.main_image,'')) NOT LIKE 'http%%')
                ORDER BY t.id""", (pk,))
        elif stat_type == "ing_img":
            cur = db_execute(conn, f"""SELECT {sel} FROM titles t
                JOIN article_content ac ON ac.title_id = t.id AND ac.language_code = 'en'
                WHERE t.domain_id = ? AND ac.ingredient_image IS NOT NULL AND TRIM(ac.ingredient_image) LIKE 'http%%'
                ORDER BY t.id""", (pk,))
        elif stat_type == "no_ing_img":
            cur = db_execute(conn, f"""SELECT {sel} FROM titles t
                LEFT JOIN article_content ac ON ac.title_id = t.id AND ac.language_code = 'en'
                WHERE t.domain_id = ? AND (ac.id IS NULL OR ac.ingredient_image IS NULL OR TRIM(COALESCE(ac.ingredient_image,'')) NOT LIKE 'http%%')
                ORDER BY t.id""", (pk,))
        elif stat_type == "pin_img":
            cur = db_execute(conn, f"""SELECT {sel} FROM titles t
                JOIN article_content ac ON ac.title_id = t.id AND ac.language_code = 'en'
                WHERE t.domain_id = ? AND ac.pin_image IS NOT NULL AND TRIM(ac.pin_image) LIKE 'http%%'
                ORDER BY t.id""", (pk,))
        elif stat_type == "no_pin_img":
            cur = db_execute(conn, f"""SELECT {sel} FROM titles t
                LEFT JOIN article_content ac ON ac.title_id = t.id AND ac.language_code = 'en'
                WHERE t.domain_id = ? AND (ac.id IS NULL OR ac.pin_image IS NULL OR TRIM(COALESCE(ac.pin_image,'')) NOT LIKE 'http%%')
                ORDER BY t.id""", (pk,))
        else:
            return jsonify({"error": "Invalid type"}), 400

        def _img(v):
            s = (v or "").strip()
            return s if s.startswith("http") else None
        articles = []
        for r in cur.fetchall():
            row = dict_row(r)
            main_url = _img(row.get("main_image"))
            ing_url = _img(row.get("ingredient_image"))
            pin_url = _img(row.get("pin_image"))
            prompt_ok = bool((row.get("prompt") or "").strip()) and bool((row.get("prompt_image_ingredients") or "").strip())
            content_ok = bool((row.get("article_html") or "").strip()) and bool((row.get("article_css") or "").strip())
            a = {
                "id": row.get("id"),
                "title": (row.get("title") or "")[:80],
                "has_prompt": prompt_ok,
                "has_main": bool(main_url),
                "has_ing": bool(ing_url),
                "has_pin": bool(pin_url),
                "has_content": content_ok,
            }
            if main_url: a["main_image"] = main_url
            if ing_url: a["ingredient_image"] = ing_url
            if pin_url: a["pin_image"] = pin_url
            articles.append(a)
    
    return jsonify({"articles": articles, "count": len(articles), "type": stat_type, "domain_id": pk})


@app.route("/api/domains/<int:pk>/article-count", methods=["GET"])
def api_domain_article_count(pk):
    """Return count and with_html (titles with generated HTML+CSS) for this domain."""
    with get_connection() as conn:
        cur = db_execute(conn, "SELECT COUNT(*) AS n FROM titles WHERE domain_id = ?", (pk,))
        row = dict_row(cur.fetchone())
        n = (row.get('n', 0) if row else 0) or 0
        cur = db_execute(conn, """
            SELECT COUNT(*) AS n FROM article_content ac
            JOIN titles t ON t.id = ac.title_id AND t.domain_id = ?
            WHERE ac.language_code = 'en'
              AND TRIM(IFNULL(ac.article_html,'')) != '' AND TRIM(IFNULL(ac.article_css,'')) != ''
        """, (pk,))
        row = dict_row(cur.fetchone())
        with_html = (row.get('n', 0) if row else 0) or 0
    return jsonify({"count": n, "with_html": with_html})


@app.route("/api/domains/<int:pk>/website-template", methods=["PUT"])
def api_domain_website_template_put(pk):
    """Update website_template for a domain. Body: { website_template: string, clear_article_content: bool }.
    When clear_article_content is True, clears article_html and article_css for all article_content of titles in this domain."""
    data = request.get_json(silent=True) or {}
    template = (data.get("website_template") or "").strip() or None
    clear_content = data.get("clear_article_content") is True
    with get_connection() as conn:
        db_execute(conn, "UPDATE domains SET website_template = ? WHERE id = ?", (template, pk))
        if clear_content:
            db_execute(conn, """
                UPDATE article_content SET article_html = '', article_css = ''
                WHERE language_code = 'en' AND title_id IN (SELECT id FROM titles WHERE domain_id = ?)
            """, (pk,))
    return jsonify({"success": True, "website_template": template})


@app.route("/api/pinterest-suggest-boards", methods=["POST"])
@login_required
def api_pinterest_suggest_boards():
    """Generate N Pinterest board names by AI. Body: count (int), context (str, optional), existing (list of names/slugs to avoid)."""
    user = get_current_user()
    user_id = user["id"]
    data = request.get_json(silent=True) or {}
    req = {**data, **dict(request.args)}
    ai = _parse_content_ai_params(req)
    user_config = get_user_config_for_api(user_id)
    openai_key = user_config.get("openai_api_key")
    openrouter_key = user_config.get("openrouter_api_key")
    groq_key = user_config.get("groq_api_key")
    if not openai_key and not openrouter_key and not groq_key:
        return jsonify({"success": False, "error": "OpenAI, OpenRouter, or Groq API key not configured in your profile"}), 400
    ai_provider = (ai.get("ai_provider") or user_config.get("ai_provider") or "").strip().lower()
    if ai_provider not in ("openrouter", "openai", "groq"):
        ai_provider = "openrouter" if openrouter_key else ("groq" if groq_key else "openai")
    if ai_provider == "openrouter" and not openrouter_key:
        ai_provider = "groq" if groq_key else ("openai" if openai_key else "openrouter")
    if ai_provider == "openai" and not openai_key:
        ai_provider = "openrouter" if openrouter_key else ("groq" if groq_key else "openai")
    if ai_provider == "groq" and not groq_key:
        ai_provider = "openrouter" if openrouter_key else ("openai" if openai_key else "groq")
    count = data.get("count")
    try:
        count = int(count) if count is not None else 5
    except (TypeError, ValueError):
        count = 5
    count = max(1, min(30, count))
    context = (data.get("context") or "recipes, food").strip() or "recipes, food"
    existing = data.get("existing") or []
    if isinstance(existing, list):
        existing = [str(x).strip().lower() for x in existing if x]
    else:
        existing = []
    existing_set = set(existing)

    def _slug(s):
        return (s or "").strip().lower().replace(" ", "-").replace("_", "-")[:64]

    try:
        import openai
        if ai_provider == "openrouter":
            client = openai.OpenAI(base_url="https://openrouter.ai/api/v1", api_key=openrouter_key)
            ai_model = ai.get("openrouter_model") or user_config.get("openrouter_model") or "openai/gpt-4o-mini"
        elif ai_provider == "groq":
            client = openai.OpenAI(base_url="https://api.groq.com/openai/v1", api_key=groq_key)
            ai_model = ai.get("groq_model") or user_config.get("groq_model") or "llama-3.3-70b-versatile"
        else:
            client = openai.OpenAI(api_key=openai_key)
            ai_model = ai.get("openai_model") or user_config.get("openai_model") or "gpt-4o-mini"

        existing_str = ", ".join(repr(x) for x in (existing[:50] or ["(none)"]))
        prompt = f"""Generate exactly {count} Pinterest board names for a food/recipe site. Theme/category: {context}.

RULES:
1. Return ONLY a JSON array of strings, e.g. ["Board One", "Board Two", ...]. No markdown, no explanation.
2. Each name must be short (1-4 words), title-case, suitable for a Pinterest board.
3. Do NOT use any of these existing names or slugs (avoid duplicates): {existing_str}
4. All {count} names must be different from each other.
5. Names should fit the theme "{context}" (e.g. Desserts, Chicken Recipes, Drinks, Vegetarian)."""

        resp = client.chat.completions.create(
            model=ai_model,
            messages=[{"role": "user", "content": prompt}],
            temperature=0.8,
            max_tokens=500,
        )
        content = (resp.choices[0].message.content or "").strip()
        content = content.replace("```json", "").replace("```", "").strip()
        raw = json.loads(content)
        if not isinstance(raw, list):
            raw = [raw] if raw else []
        names = []
        seen_slugs = set(existing_set)
        for item in raw:
            name = (item if isinstance(item, str) else str(item)).strip()
            if not name or len(name) > 100:
                continue
            slug = _slug(name)
            if slug and slug not in seen_slugs:
                seen_slugs.add(slug)
                names.append(name)
        return jsonify({"success": True, "names": names[:count]})
    except json.JSONDecodeError as e:
        return jsonify({"success": False, "error": f"Invalid response: {e}"}), 500
    except Exception as e:
        log.exception("[pinterest-suggest-boards] %s", e)
        return jsonify({"success": False, "error": str(e)}), 500


@app.route("/api/generate-color-palette", methods=["POST"])
@login_required
def api_generate_color_palette():
    """Use OpenAI to generate a matching color palette with guaranteed text contrast for recipe blogs."""
    user = get_current_user()
    user_config = get_user_config_for_api(user["id"])
    openai_key = user_config.get("openai_api_key")
    openrouter_key = user_config.get("openrouter_api_key")
    
    if not openai_key and not openrouter_key:
        return jsonify({"success": False, "error": "OpenAI or OpenRouter API key not configured in your profile"}), 500
    try:
        if openrouter_key:
            import openai
            client = openai.OpenAI(base_url="https://openrouter.ai/api/v1", api_key=openrouter_key)
            ai_model = user_config.get("openrouter_model") or "openai/gpt-4o-mini"
        else:
            import openai
            client = openai.OpenAI(api_key=openai_key)
            ai_model = user_config.get("openai_model") or "gpt-4o-mini"
            
        prompt = """Generate a single harmonious color palette for a recipe/food blog. Return ONLY valid JSON, no markdown.

RULES (mandatory):
1. Keys: primary, secondary, background, text_primary, text_secondary, border
2. All values must be hex: #RRGGBB (e.g. #6C8AE4)
3. CONTRAST: text_primary and text_secondary must be readable on background. Light background (#fff, #f9f9f9, #f5f5f5) → dark text (#1a1a1a, #2D2D2D, #333). Dark background → light text (#fff, #f5f5f5). Never dark text on dark background.
4. primary: accent for links, buttons, headings. secondary: complementary. background: page bg. border: subtle border, slightly darker/lighter than background.
5. Colors must be harmonious (e.g. warm coral+cream, sage green, navy+gold, terracotta). Vary the theme each time.

Output format:
{"primary":"#hex","secondary":"#hex","background":"#hex","text_primary":"#hex","text_secondary":"#hex","border":"#hex"}"""
        resp = client.chat.completions.create(
            model=ai_model,
            messages=[{"role": "user", "content": prompt}],
            temperature=0.9,
            max_tokens=400,
        )
        content = (resp.choices[0].message.content or "").strip()
        content = content.replace("```json", "").replace("```", "").strip()
        data = json.loads(content)
        keys = ["primary", "secondary", "background", "text_primary", "text_secondary", "border"]
        palette = {}
        for k in keys:
            v = (data.get(k) or "").strip()
            if v and v.startswith("#") and len(v) == 7:
                palette[k] = v.upper()
            else:
                palette[k] = (dict(DEFAULT_DOMAIN_COLORS)).get(k, "#888888")
        return jsonify({"success": True, "colors": palette})
    except json.JSONDecodeError as e:
        return jsonify({"success": False, "error": f"Invalid palette JSON: {e}"}), 500
    except Exception as e:
        log.error(f"[generate-color-palette] Error: {e}", exc_info=True)
        return jsonify({"success": False, "error": str(e)}), 500


@app.route("/api/domains/<int:pk>/colors", methods=["GET"])
def api_domain_colors_get(pk):
    """Return all colors for a domain (domain_colors + article_template_config.colors merged)."""
    base_keys = set(DEFAULT_DOMAIN_COLORS) | set(DEFAULT_EXTENDED_COLORS)
    defaults = dict(DEFAULT_DOMAIN_COLORS, **DEFAULT_EXTENDED_COLORS)
    colors = dict(defaults)
    with get_connection() as conn:
        cur = db_execute(conn, "SELECT domain_colors, article_template_config FROM domains WHERE id = ?", (pk,))
        row = cur.fetchone()
    if not row:
        return jsonify({"error": "Domain not found"}), 404
    d = dict_row(row)
    raw_dc = (d.get("domain_colors") or "").strip()
    if raw_dc:
        try:
            dc = json.loads(raw_dc)
            if isinstance(dc, dict):
                for k, v in dc.items():
                    if v and k in base_keys:
                        colors[k] = str(v)
        except Exception:
            pass
    raw_atc = (d.get("article_template_config") or "").strip()
    if raw_atc:
        try:
            atc = json.loads(raw_atc) if isinstance(raw_atc, str) else raw_atc
            if isinstance(atc, dict):
                atc_colors = atc.get("colors") or {}
                if isinstance(atc_colors, dict):
                    for k, v in atc_colors.items():
                        if v and k in base_keys:
                            colors[k] = str(v)
        except Exception:
            pass
    return jsonify({"success": True, "colors": colors, "groups": DOMAIN_COLOR_GROUPS})


@app.route("/api/domains/<int:pk>/colors", methods=["PUT"])
def api_domain_colors_put(pk):
    """Save domain_colors for a domain. Body: { colors: { primary, secondary, ... }, update_articles: bool }."""
    data = request.get_json(silent=True) or {}
    colors = data.get("colors")
    update_articles = data.get("update_articles", True)
    if not isinstance(colors, dict):
        return jsonify({"success": False, "error": "colors object required"}), 400
    base_keys = set(DEFAULT_DOMAIN_COLORS) | set(DEFAULT_EXTENDED_COLORS)
    merged = dict(DEFAULT_DOMAIN_COLORS, **DEFAULT_EXTENDED_COLORS)
    for k, v in colors.items():
        if v and k in base_keys:
            merged[k] = str(v).strip()
    with get_connection() as conn:
        cur = db_execute(conn, "SELECT domain_colors FROM domains WHERE id = ?", (pk,))
        old_row = cur.fetchone()
        old_colors = {}
        if old_row:
            raw = (dict_row(old_row).get("domain_colors") or "").strip()
            if raw:
                try:
                    parsed = json.loads(raw)
                    if isinstance(parsed, dict):
                        old_colors = {k: str(v) for k, v in parsed.items() if v}
                except (json.JSONDecodeError, TypeError):
                    pass
        db_execute(conn, "UPDATE domains SET domain_colors = ? WHERE id = ?", (json.dumps(merged), pk))
        # Sync article_template_config.colors so Article Editor and future generation use same palette
        cur = db_execute(conn, "SELECT article_template_config FROM domains WHERE id = ?", (pk,))
        row = cur.fetchone()
        if row:
            cfg_raw = (dict_row(row).get("article_template_config") or "").strip()
            if cfg_raw:
                try:
                    cfg = json.loads(cfg_raw) if isinstance(cfg_raw, str) else cfg_raw
                    if isinstance(cfg, dict):
                        cfg.setdefault("colors", {})
                        if isinstance(cfg.get("colors"), dict):
                            for k, v in merged.items():
                                if v:
                                    cfg["colors"][k] = v
                            db_execute(conn, "UPDATE domains SET article_template_config = ? WHERE id = ?", (json.dumps(cfg), pk))
                except (json.JSONDecodeError, TypeError):
                    pass
        # Replace old colors in visual_customizations (styles from Visual Editor) so theme changes propagate
        vc_updated = _update_visual_customizations_colors(conn, pk, old_colors, merged)
        articles_updated = 0
        if update_articles:
            cur = db_execute(conn, "SELECT t.id FROM titles t WHERE t.domain_id = ?", (pk,))
            title_ids = [dict_row(r).get("id") for r in cur.fetchall()]
            if title_ids:
                for tid in title_ids:
                    try:
                        _update_article_colors(conn, tid, merged, old_colors)
                        articles_updated += 1
                    except Exception:
                        pass
    
    # Regenerate site parts (header, footer, sidebar, category) with new colors
    parts_regenerated = _regenerate_domain_site_parts(pk, merged)
    
    return jsonify({
        "success": True,
        "articles_updated": articles_updated,
        "parts_regenerated": parts_regenerated,
        "visual_customizations_updated": vc_updated,
        "note": "Colors updated. Headers, footers, sidebars, and visual customizations refreshed."
    })


@app.route("/api/domains/<int:pk>/fonts", methods=["GET"])
def api_domain_fonts_get(pk):
    """Return domain_fonts for a domain (heading_family, body_family, sizes, etc.)."""
    with get_connection() as conn:
        cur = db_execute(conn, "SELECT domain_fonts FROM domains WHERE id = ?", (pk,))
        row = cur.fetchone()
    if not row:
        return jsonify({"error": "Domain not found"}), 404
    d = dict_row(row)
    raw = (d.get("domain_fonts") or "").strip()
    fonts = dict(DEFAULT_DOMAIN_FONTS)
    if raw:
        try:
            parsed = json.loads(raw)
            if isinstance(parsed, dict):
                for k, v in parsed.items():
                    if v:
                        fonts[k] = str(v)
        except Exception:
            pass
    return jsonify({"success": True, "fonts": fonts})


@app.route("/api/domains/<int:pk>/fonts", methods=["PUT"])
def api_domain_fonts_put(pk):
    """Save domain_fonts. Body: { fonts: { heading_family, body_family, ... }, update_articles: bool }."""
    data = request.get_json(silent=True) or {}
    fonts_in = data.get("fonts")
    update_articles = data.get("update_articles", True)
    if not isinstance(fonts_in, dict):
        return jsonify({"success": False, "error": "fonts object required"}), 400
    merged = dict(DEFAULT_DOMAIN_FONTS)
    for k in list(DEFAULT_DOMAIN_FONTS.keys()):
        v = fonts_in.get(k)
        if v is not None and str(v).strip():
            merged[k] = str(v).strip()
    with get_connection() as conn:
        db_execute(conn, "UPDATE domains SET domain_fonts = ? WHERE id = ?", (json.dumps(merged), pk))
        # Sync article_template_config.fonts
        cur = db_execute(conn, "SELECT article_template_config FROM domains WHERE id = ?", (pk,))
        row = cur.fetchone()
        if row:
            cfg_raw = (dict_row(row).get("article_template_config") or "").strip()
            if cfg_raw:
                try:
                    cfg = json.loads(cfg_raw) if isinstance(cfg_raw, str) else cfg_raw
                    if isinstance(cfg, dict):
                        cfg["fonts"] = _domain_fonts_to_config(json.dumps(merged))
                        db_execute(conn, "UPDATE domains SET article_template_config = ? WHERE id = ?", (json.dumps(cfg), pk))
                except (json.JSONDecodeError, TypeError):
                    pass
    # Regenerate site parts with new fonts
    config = {"colors": dict(DEFAULT_DOMAIN_COLORS), "fonts": _domain_fonts_to_config(json.dumps(merged))}
    with get_connection() as conn:
        cur = db_execute(conn, "SELECT domain_colors FROM domains WHERE id = ?", (pk,))
        r = cur.fetchone()
        if r:
            dc_raw = (dict_row(r).get("domain_colors") or "").strip()
            if dc_raw:
                try:
                    dc = json.loads(dc_raw)
                    if isinstance(dc, dict):
                        config["colors"] = {k: v for k, v in dc.items() if v}
                except Exception:
                    pass
    _regenerate_domain_site_parts(pk, config.get("colors", {}))
    return jsonify({"success": True, "note": "Fonts saved; site parts regenerated"})


@app.route("/api/domains/<int:pk>/articles-list")
def api_domain_articles_list(pk):
    """Return paginated list of titles for domain. Params: filter=all|no_prompt|no_main|no_ing|no_pin|no_content|not_validated|validated (default not_validated).
    Legacy: validated=0|1|all, content=any|empty (used when filter not set)."""
    offset = max(0, int(request.args.get("offset", 0)))
    limit = min(100, max(1, int(request.args.get("limit", 30))))
    filter_val = (request.args.get("filter") or request.args.get("filter_type") or "").strip().lower()
    validated_filter = (request.args.get("validated") or "").strip().lower()
    content_filter = (request.args.get("content") or "any").strip().lower()
    if content_filter not in ("any", "empty"):
        content_filter = "any"
    valid_filters = ("all", "no_prompt", "no_main", "no_ing", "no_pin", "no_content", "not_validated", "validated")
    if filter_val not in valid_filters:
        filter_val = ""
    if not filter_val:
        if validated_filter == "1":
            filter_val = "validated"
        elif validated_filter == "all":
            filter_val = "all"
        elif content_filter == "empty":
            filter_val = "no_content"
        elif validated_filter in ("0", ""):
            filter_val = "not_validated"
    with get_connection() as conn:
        base_where = "t.domain_id = ?"
        filter_where = ""
        if filter_val == "all":
            filter_where = ""
        elif filter_val == "no_prompt":
            filter_where = " AND (ac.id IS NULL OR TRIM(COALESCE(ac.prompt,'')) = '' OR TRIM(COALESCE(ac.prompt_image_ingredients,'')) = '')"
        elif filter_val == "no_main":
            filter_where = " AND (ac.id IS NULL OR ac.main_image IS NULL OR TRIM(COALESCE(ac.main_image,'')) NOT LIKE 'http%')"
        elif filter_val == "no_ing":
            filter_where = " AND (ac.id IS NULL OR ac.ingredient_image IS NULL OR TRIM(COALESCE(ac.ingredient_image,'')) NOT LIKE 'http%')"
        elif filter_val == "no_pin":
            filter_where = " AND (ac.id IS NULL OR ac.pin_image IS NULL OR TRIM(COALESCE(ac.pin_image,'')) NOT LIKE 'http%')"
        elif filter_val == "no_content":
            filter_where = " AND (ac.id IS NULL OR TRIM(COALESCE(ac.article_html,'')) = '' OR TRIM(COALESCE(ac.article_css,'')) = '')"
        elif filter_val == "not_validated":
            # Titles with ALL steps completed (prompt, main, ing, content, pin) but not yet validated
            filter_where = """ AND ac.id IS NOT NULL
                AND TRIM(COALESCE(ac.prompt,'')) != '' AND TRIM(COALESCE(ac.prompt_image_ingredients,'')) != ''
                AND ac.main_image IS NOT NULL AND TRIM(COALESCE(ac.main_image,'')) LIKE 'http%'
                AND ac.ingredient_image IS NOT NULL AND TRIM(COALESCE(ac.ingredient_image,'')) LIKE 'http%'
                AND ac.pin_image IS NOT NULL AND TRIM(COALESCE(ac.pin_image,'')) LIKE 'http%'
                AND TRIM(COALESCE(ac.article_html,'')) != '' AND TRIM(COALESCE(ac.article_css,'')) != ''
                AND COALESCE(ac.validated, 0) = 0"""
        elif filter_val == "validated":
            filter_where = " AND ac.id IS NOT NULL AND COALESCE(ac.validated, 0) = 1"
        cur = db_execute(conn, """
            SELECT COUNT(*) AS total FROM titles t
            LEFT JOIN article_content ac ON ac.title_id = t.id AND ac.language_code = 'en'
            WHERE """ + base_where + filter_where, (pk,))
        row = dict_row(cur.fetchone())
        total = (row.get("total") or 0) or 0
        cur = db_execute(conn, """
            SELECT t.id, t.title, t.domain_id, t.group_id, d.group_id AS domain_group_id, d.domain_index,
                   ac.generated_at, ac.model_used, COALESCE(ac.validated, 0) AS validated,
                   ac.prompt, ac.prompt_image_ingredients, ac.main_image, ac.ingredient_image, ac.pin_image,
                   ac.article_html, ac.article_css
            FROM titles t
            JOIN domains d ON t.domain_id = d.id
            LEFT JOIN article_content ac ON ac.title_id = t.id AND ac.language_code = 'en'
            WHERE """ + base_where + filter_where + """
            ORDER BY t.id DESC LIMIT ? OFFSET ?
        """, (pk, limit, offset))
        rows = cur.fetchall()
    items = []
    for r in rows:
        row = dict_row(r)
        # A–D siblings must use the domain's batch (domains.group_id). titles.group_id can stay stale after moves.
        batch_gid = row.get("domain_group_id")
        if batch_gid is None:
            batch_gid = row.get("group_id")
        title_text = (row.get("title") or "").strip()
        siblings = {}
        if batch_gid is not None and title_text:
            with get_connection() as conn2:
                cur2 = db_execute(conn2, """
                    SELECT t.id, d.domain_index
                    FROM titles t
                    JOIN domains d ON t.domain_id = d.id
                    WHERE d.group_id = ? AND t.title = ? AND d.domain_index IN (0,1,2,3)
                    ORDER BY d.domain_index
                """, (batch_gid, row.get("title") or ""))
                for r2 in cur2.fetchall():
                    d = dict_row(r2)
                    idx = d.get("domain_index")
                    if idx is not None and 0 <= idx < 4:
                        siblings["ABCD"[idx]] = d.get("id")
        gen_at = row.get("generated_at")
        is_validated = bool(row.get("validated"))
        prompt_ok = bool((row.get("prompt") or "").strip()) and bool((row.get("prompt_image_ingredients") or "").strip())
        main_ok = bool((row.get("main_image") or "").strip() and str(row.get("main_image") or "").startswith("http"))
        ing_ok = bool((row.get("ingredient_image") or "").strip() and str(row.get("ingredient_image") or "").startswith("http"))
        pin_ok = bool((row.get("pin_image") or "").strip() and str(row.get("pin_image") or "").startswith("http"))
        content_ok = bool((row.get("article_html") or "").strip()) and bool((row.get("article_css") or "").strip())
        items.append({
            "id": row.get("id"),
            "title": title_text,
            "generated_at": str(gen_at)[:19] if gen_at else None,
            "model_used": (row.get("model_used") or "").strip() or None,
            "domain_index": row.get("domain_index"),
            "validated": is_validated,
            "siblings": siblings,
            "has_prompt": prompt_ok,
            "has_main": main_ok,
            "has_ing": ing_ok,
            "has_pin": pin_ok,
            "has_content": content_ok,
        })
    return jsonify({"total": total, "items": items, "offset": offset, "limit": limit})


@app.route("/api/articles-list")
def api_articles_list():
    """Return paginated articles across all domains (or one domain). Params: offset, limit, validated=0|1|all (default 0), domain_id (optional). Each item includes domain_id, domain_url."""
    offset = max(0, int(request.args.get("offset", 0)))
    limit = min(100, max(1, int(request.args.get("limit", 30))))
    validated_filter = (request.args.get("validated") or "0").strip().lower()
    if validated_filter not in ("0", "1", "all"):
        validated_filter = "0"
    domain_id_param = request.args.get("domain_id", "").strip()
    domain_id = int(domain_id_param) if domain_id_param.isdigit() else None
    validated_where = ""
    if validated_filter == "0":
        validated_where = " AND (ac.id IS NULL OR COALESCE(ac.validated, 0) = 0)"
    elif validated_filter == "1":
        validated_where = " AND ac.id IS NOT NULL AND COALESCE(ac.validated, 0) = 1"
    with get_connection() as conn:
        if domain_id is not None:
            base_where = "t.domain_id = ?"
            params_count = (domain_id,)
            params_list = (domain_id, limit, offset)
        else:
            base_where = "1 = 1"
            params_count = ()
            params_list = (limit, offset)
        cur = db_execute(conn, """
            SELECT COUNT(*) AS total FROM titles t
            LEFT JOIN article_content ac ON ac.title_id = t.id AND ac.language_code = 'en'
            WHERE """ + base_where + validated_where, params_count)
        row = dict_row(cur.fetchone())
        total = (row.get("total") or 0) or 0
        cur = db_execute(conn, """
            SELECT t.id, t.title, t.domain_id, t.group_id, d.group_id AS domain_group_id, d.domain_index, d.domain_url, d.domain_name, d.website_template,
                   ac.generated_at, ac.model_used, COALESCE(ac.validated, 0) AS validated
            FROM titles t
            JOIN domains d ON t.domain_id = d.id
            LEFT JOIN article_content ac ON ac.title_id = t.id AND ac.language_code = 'en'
            WHERE """ + base_where + validated_where + """
            ORDER BY t.id DESC LIMIT ? OFFSET ?
        """, params_list)
        rows = cur.fetchall()
    items = []
    for r in rows:
        row = dict_row(r)
        batch_gid = row.get("domain_group_id")
        if batch_gid is None:
            batch_gid = row.get("group_id")
        title_text = (row.get("title") or "").strip()
        siblings = {}
        if batch_gid is not None and title_text:
            with get_connection() as conn2:
                cur2 = db_execute(conn2, """
                    SELECT t.id, d.domain_index
                    FROM titles t
                    JOIN domains d ON t.domain_id = d.id
                    WHERE d.group_id = ? AND t.title = ? AND d.domain_index IN (0,1,2,3)
                    ORDER BY d.domain_index
                """, (batch_gid, row.get("title") or ""))
                for r2 in cur2.fetchall():
                    d = dict_row(r2)
                    idx = d.get("domain_index")
                    if idx is not None and 0 <= idx < 4:
                        siblings["ABCD"[idx]] = d.get("id")
        gen_at = row.get("generated_at")
        domain_url = (row.get("domain_url") or row.get("domain_name") or "").strip() or "—"
        generator = (row.get("website_template") or "").strip() or None
        items.append({
            "id": row.get("id"),
            "title": title_text,
            "generated_at": str(gen_at)[:19] if gen_at else None,
            "model_used": (row.get("model_used") or "").strip() or None,
            "domain_id": row.get("domain_id"),
            "domain_url": domain_url,
            "domain_index": row.get("domain_index"),
            "validated": bool(row.get("validated")),
            "siblings": siblings,
            "generator": generator,
        })
    return jsonify({"total": total, "items": items, "offset": offset, "limit": limit})


@app.route("/api/all-articles-test-content", methods=["POST"])
def api_all_articles_test_content():
    """Run content generation for the first article of each filtered domain, or specific title_ids. Body: {validated, domain_id, title_ids, async}."""
    req = request.get_json(silent=True) or {}
    validated_filter = str(req.get("validated", "0")).strip().lower()
    if validated_filter not in ("0", "1", "all"):
        validated_filter = "0"
    domain_id_raw = str(req.get("domain_id", "")).strip()
    domain_id = int(domain_id_raw) if domain_id_raw.isdigit() else None
    async_mode = str(req.get("async", "1")).lower() in ("1", "true", "yes")
    ai_provider = (req.get("ai_provider") or "").strip() or None
    openrouter_models = _parse_openrouter_models(req)
    openai_model = (req.get("openai_model") or "").strip() or None
    openrouter_model = (req.get("openrouter_model") or "").strip() or None
    local_model = (req.get("local_model") or "").strip() or None
    llamacpp_model_id = req.get("llamacpp_model_id")
    if llamacpp_model_id is not None and str(llamacpp_model_id).strip():
        try:
            llamacpp_model_id = int(llamacpp_model_id)
        except (TypeError, ValueError):
            llamacpp_model_id = None
    else:
        llamacpp_model_id = None
    groq_model = _parse_groq_model(req)
    user = get_current_user()
    user_id = user["id"] if user else None

    # Support retry via title_ids
    explicit_title_ids = req.get("title_ids") or []
    if not isinstance(explicit_title_ids, list):
        explicit_title_ids = []
    explicit_title_ids = [int(x) for x in explicit_title_ids if str(x).isdigit()]

    if not async_mode:
        return jsonify({"success": False, "error": "Only async mode supported"}), 400

    # If title_ids provided, use them directly (retry mode)
    if explicit_title_ids:
        title_ids = explicit_title_ids
        with get_connection() as conn:
            placeholders = ",".join("?" * len(title_ids))
            cur = db_execute(conn, f"SELECT DISTINCT domain_id FROM titles WHERE id IN ({placeholders})", title_ids)
            domain_ids = [r[0] for r in cur.fetchall()]
    else:
        # Otherwise, query first article per domain (test mode)
        validated_where = ""
        if validated_filter == "0":
            validated_where = " AND (ac.id IS NULL OR COALESCE(ac.validated, 0) = 0)"
        elif validated_filter == "1":
            validated_where = " AND ac.id IS NOT NULL AND COALESCE(ac.validated, 0) = 1"

        with get_connection() as conn:
            if domain_id is not None:
                base_where = "t.domain_id = ?"
                params = (domain_id,)
            else:
                base_where = "1 = 1"
                params = ()
            cur = db_execute(conn, """
                SELECT t.domain_id, MIN(t.id) AS title_id
                FROM titles t
                LEFT JOIN article_content ac ON ac.title_id = t.id AND ac.language_code = 'en'
                WHERE """ + base_where + validated_where + """
                GROUP BY t.domain_id
                ORDER BY t.domain_id
            """, params)
            pairs = [dict_row(r) for r in cur.fetchall()]

        title_ids = [int(p.get("title_id")) for p in pairs if p and p.get("title_id")]
        domain_ids = [int(p.get("domain_id")) for p in pairs if p and p.get("domain_id")]
    
    if not title_ids:
        return jsonify({"success": False, "error": "No matching domains/articles found"}), 400

    job_id = str(uuid.uuid4())
    _bulk_progress[job_id] = {
        "status": "running",
        "message": f"Starting test for {len(title_ids)} domain(s)...",
        "current_title": "",
        "type": "test_content",
        "action": "Test content",
        "mode": "article",
        "domain_id": domain_id,
        "domain_ids": domain_ids,
        "total_rows": len(title_ids),
        "done": 0,
        "ok": 0,
        "failed": 0,
        "created_at": time.time(),
        "steps": [],
    }

    def task():
        ok, failed = 0, 0
        try:
            for idx, tid in enumerate(title_ids):
                if _bulk_cancel.get(job_id):
                    break
                with get_connection() as conn:
                    cur = db_execute(conn, """
                        SELECT t.title, t.domain_id, d.domain_url, d.domain_name
                        FROM titles t
                        LEFT JOIN domains d ON d.id = t.domain_id
                        WHERE t.id = ?
                    """, (tid,))
                    row = dict_row(cur.fetchone()) or {}
                ttitle = (row.get("title") or "")[:60]
                durl = (row.get("domain_url") or row.get("domain_name") or f"id {row.get('domain_id')}")
                _bulk_progress[job_id].update({
                    "message": f"Testing {idx + 1}/{len(title_ids)}",
                    "current_title": f"[{durl}] {ttitle}",
                    "done": idx,
                })
                try:
                    _do_generate_article_external(tid, ai_provider=ai_provider, openrouter_models=openrouter_models, openai_model=openai_model, openrouter_model=openrouter_model, local_model=local_model, llamacpp_model_id=llamacpp_model_id, groq_model=groq_model, user_id=user_id)
                    ok += 1
                    _bulk_progress[job_id].get("steps", []).append(f"R{idx+1}: [{tid}] {ttitle} ✓")
                except Exception as e:
                    failed += 1
                    _bulk_progress[job_id].get("steps", []).append(f"R{idx+1}: [{tid}] {ttitle} ✗ | {str(e)[:80]}")
            if _bulk_cancel.get(job_id):
                _bulk_progress[job_id].update({
                    "status": "cancelled",
                    "message": f"Cancelled. {ok} done" + (f", {failed} failed" if failed else ""),
                    "ok": ok,
                    "failed": failed,
                    "done": ok + failed,
                })
            else:
                _bulk_progress[job_id].update({
                    "status": "done",
                    "message": f"Test finished: {ok} done" + (f", {failed} failed" if failed else ""),
                    "ok": ok,
                    "failed": failed,
                    "done": ok + failed,
                })
        except Exception as e:
            err = str(e)[:BULK_ERROR_DETAIL_MAX]
            _bulk_progress[job_id].update({"status": "error", "message": err, "error_detail": err, "ok": ok, "failed": failed})

    threading.Thread(target=task, daemon=True).start()
    return jsonify({"success": True, "job_id": job_id, "count": len(title_ids), "domain_ids": domain_ids})


@app.route("/api/domains/<int:pk>/stats-articles")
def api_domain_stats_articles(pk):
    """Return articles for domain filtered by type: html_css, no_html_css, main_img, no_main_img, ing_img, no_ing_img, pin_img, no_pin_img. Includes actions_html and group_id for Run UI."""
    stype = (request.args.get("type") or "").strip() or "html_css"
    if stype not in ("prompt", "no_prompt", "html_css", "no_html_css", "main_img", "no_main_img", "ing_img", "no_ing_img", "pin_img", "no_pin_img"):
        stype = "html_css"
    with get_connection() as conn:
        cur = db_execute(conn, "SELECT group_id, domain_index FROM domains WHERE id = ?", (pk,))
        dom_row = dict_row(cur.fetchone())
    group_id = dom_row.get("group_id") if dom_row else None
    domain_index = dom_row.get("domain_index") if dom_row is not None else 0
    if domain_index is None or domain_index not in (0, 1, 2, 3):
        domain_index = 0
    ac_map = {}
    with get_connection() as conn:
        cur = db_execute(conn, "SELECT title_id, recipe, article_html, article_css, main_image, ingredient_image, pin_image FROM article_content WHERE language_code = 'en'")
        for r in cur.fetchall():
            row = dict_row(r)
            rid = row.get("title_id")
            recipe_ok = bool((row.get("recipe") or "").strip())
            article_html_ok = bool((row.get("article_html") or "").strip())
            article_css_ok = bool((row.get("article_css") or "").strip())
            main_img = (row.get("main_image") or "").strip()
            ing_img = (row.get("ingredient_image") or "").strip()
            pin_img = (row.get("pin_image") or "").strip()
            ac_map[rid] = {
                "has_all": recipe_ok and article_html_ok and article_css_ok,
                "main_image": main_img,
                "ingredient_image": ing_img,
                "pin_image": pin_img,
            }
    with get_connection() as conn:
        if stype == "prompt":
            cur = db_execute(conn, """SELECT t.id AS title_id, t.title, ac.main_image, ac.ingredient_image, ac.pin_image, 1 AS has_val
                FROM titles t
                JOIN article_content ac ON ac.title_id = t.id AND ac.language_code = 'en'
                WHERE t.domain_id = ? AND TRIM(COALESCE(ac.prompt,'')) != '' AND TRIM(COALESCE(ac.prompt_image_ingredients,'')) != ''
                ORDER BY t.id DESC""", (pk,))
        elif stype == "no_prompt":
            cur = db_execute(conn, """SELECT t.id AS title_id, t.title, ac.main_image, ac.ingredient_image, ac.pin_image, 0 AS has_val
                FROM titles t
                LEFT JOIN article_content ac ON ac.title_id = t.id AND ac.language_code = 'en'
                WHERE t.domain_id = ? AND (ac.id IS NULL OR TRIM(COALESCE(ac.prompt,'')) = '' OR TRIM(COALESCE(ac.prompt_image_ingredients,'')) = '')
                ORDER BY t.id DESC""", (pk,))
        elif stype == "html_css":
            cur = db_execute(conn, """SELECT t.id AS title_id, t.title, ac.main_image, ac.ingredient_image, ac.pin_image, 1 AS has_val
                FROM titles t
                LEFT JOIN article_content ac ON ac.title_id = t.id AND ac.language_code = 'en'
                WHERE t.domain_id = ? AND ac.id IS NOT NULL AND TRIM(COALESCE(ac.article_html,'')) != '' AND TRIM(COALESCE(ac.article_css,'')) != ''
                ORDER BY t.id DESC""", (pk,))
        elif stype == "no_html_css":
            cur = db_execute(conn, """SELECT t.id AS title_id, t.title, ac.main_image, ac.ingredient_image, ac.pin_image, 0 AS has_val
                FROM titles t
                LEFT JOIN article_content ac ON ac.title_id = t.id AND ac.language_code = 'en'
                WHERE t.domain_id = ? AND (ac.id IS NULL OR TRIM(COALESCE(ac.article_html,'')) = '' OR TRIM(COALESCE(ac.article_css,'')) = '')
                ORDER BY t.id DESC""", (pk,))
        elif stype == "main_img":
            cur = db_execute(conn, """SELECT t.id AS title_id, t.title, ac.main_image, ac.ingredient_image, ac.pin_image, 1 AS has_val
                FROM titles t
                JOIN article_content ac ON ac.title_id = t.id AND ac.language_code = 'en'
                WHERE t.domain_id = ? AND ac.main_image IS NOT NULL AND TRIM(ac.main_image) LIKE 'http%%'
                ORDER BY t.id DESC""", (pk,))
        elif stype == "no_main_img":
            cur = db_execute(conn, """SELECT t.id AS title_id, t.title, ac.main_image, ac.ingredient_image, ac.pin_image, 0 AS has_val
                FROM titles t
                LEFT JOIN article_content ac ON ac.title_id = t.id AND ac.language_code = 'en'
                WHERE t.domain_id = ? AND (ac.id IS NULL OR ac.main_image IS NULL OR TRIM(ac.main_image) NOT LIKE 'http%%')
                ORDER BY t.id DESC""", (pk,))
        elif stype == "ing_img":
            cur = db_execute(conn, """SELECT t.id AS title_id, t.title, ac.main_image, ac.ingredient_image, ac.pin_image, 1 AS has_val
                FROM titles t
                JOIN article_content ac ON ac.title_id = t.id AND ac.language_code = 'en'
                WHERE t.domain_id = ? AND ac.ingredient_image IS NOT NULL AND TRIM(ac.ingredient_image) LIKE 'http%%'
                ORDER BY t.id DESC""", (pk,))
        elif stype == "no_ing_img":
            cur = db_execute(conn, """SELECT t.id AS title_id, t.title, ac.main_image, ac.ingredient_image, ac.pin_image, 0 AS has_val
                FROM titles t
                LEFT JOIN article_content ac ON ac.title_id = t.id AND ac.language_code = 'en'
                WHERE t.domain_id = ? AND (ac.id IS NULL OR ac.ingredient_image IS NULL OR TRIM(ac.ingredient_image) NOT LIKE 'http%%')
                ORDER BY t.id DESC""", (pk,))
        elif stype == "pin_img":
            cur = db_execute(conn, """SELECT t.id AS title_id, t.title, ac.main_image, ac.ingredient_image, ac.pin_image, 1 AS has_val
                FROM titles t
                JOIN article_content ac ON ac.title_id = t.id AND ac.language_code = 'en'
                WHERE t.domain_id = ? AND ac.pin_image IS NOT NULL AND TRIM(ac.pin_image) LIKE 'http%%'
                ORDER BY t.id DESC""", (pk,))
        else:  # no_pin_img
            cur = db_execute(conn, """SELECT t.id AS title_id, t.title, ac.main_image, ac.ingredient_image, ac.pin_image, 0 AS has_val
                FROM titles t
                LEFT JOIN article_content ac ON ac.title_id = t.id AND ac.language_code = 'en'
                WHERE t.domain_id = ? AND (ac.id IS NULL OR ac.pin_image IS NULL OR TRIM(ac.pin_image) NOT LIKE 'http%%')
                ORDER BY t.id DESC""", (pk,))
        rows = cur.fetchall()
    articles = []
    for r in rows or []:
        ro = dict_row(r)
        title_id = ro.get("title_id")
        title_text = (ro.get("title") or "")[:100]
        ids = [None, None, None, None]
        title_a_id = None
        if group_id is not None:
            with get_connection() as conn2:
                cur2 = db_execute(conn2, """SELECT t.id, d.domain_index FROM titles t
                    JOIN domains d ON t.domain_id = d.id
                    WHERE t.group_id = ? AND t.title = ? AND d.domain_index IN (0,1,2,3)
                    ORDER BY d.domain_index""", (group_id, ro.get("title")))
                for r2 in cur2.fetchall():
                    r2d = dict_row(r2)
                    idx = r2d.get("domain_index")
                    if idx is not None and 0 <= idx < 4:
                        ids[idx] = r2d.get("id")
                if ids[0]:
                    title_a_id = ids[0]
        if not ids[0]:
            ids[0] = title_id if domain_index == 0 else None
            if domain_index == 0:
                title_a_id = title_id
            elif title_id:
                ids[domain_index] = title_id
        actions_html = _render_article_run_actions_html(ids, domain_index, ac_map, title_a_id, in_group=(group_id is not None))
        articles.append({
            "title_id": title_id,
            "id": title_id,
            "title": title_text,
            "main_image": (ro.get("main_image") or "").strip(),
            "ingredient_image": (ro.get("ingredient_image") or "").strip(),
            "pin_image": (ro.get("pin_image") or "").strip(),
            "actions_html": actions_html,
            "title_a_id": title_a_id,
        })
    labels = {
        "html_css": "Articles with HTML+CSS",
        "no_html_css": "Articles without HTML+CSS",
        "main_img": "Articles with main image",
        "no_main_img": "Articles without main image",
        "ing_img": "Articles with ingredient image",
        "no_ing_img": "Articles without ingredient image",
        "pin_img": "Articles with pin image",
        "no_pin_img": "Articles without pin image",
    }
    # Include counts for filter toggles (with_count, without_count)
    with_count = without_count = 0
    with get_connection() as conn:
        cur = db_execute(conn, """SELECT
            SUM(CASE WHEN ac.id IS NOT NULL AND TRIM(COALESCE(ac.article_html,'')) != '' AND TRIM(COALESCE(ac.article_css,'')) != '' THEN 1 ELSE 0 END) AS html_css,
            SUM(CASE WHEN ac.main_image IS NOT NULL AND TRIM(ac.main_image) LIKE 'http%%' THEN 1 ELSE 0 END) AS main_img,
            SUM(CASE WHEN ac.ingredient_image IS NOT NULL AND TRIM(ac.ingredient_image) LIKE 'http%%' THEN 1 ELSE 0 END) AS ing_img,
            SUM(CASE WHEN ac.pin_image IS NOT NULL AND TRIM(ac.pin_image) LIKE 'http%%' THEN 1 ELSE 0 END) AS pin_img,
            COUNT(DISTINCT t.id) AS total
            FROM titles t
            LEFT JOIN article_content ac ON ac.title_id = t.id AND ac.language_code = 'en'
            WHERE t.domain_id = ?""", (pk,))
        row = dict_row(cur.fetchone())
        total = row.get("total") or 0
        html_css_n = row.get("html_css") or 0
        main_img_n = row.get("main_img") or 0
        ing_img_n = row.get("ing_img") or 0
    counts = {
        "html_css": {"with": html_css_n, "without": total - html_css_n},
        "main_img": {"with": main_img_n, "without": total - main_img_n},
        "ing_img": {"with": ing_img_n, "without": total - ing_img_n},
    }
    return jsonify({
        "success": True,
        "articles": articles,
        "type": stype,
        "label": labels.get(stype, stype),
        "group_id": group_id,
        "counts": counts,
    })


