@app.route("/api/users/create", methods=["POST"])
@login_required
def api_users_create():
    if not get_current_user().get("is_admin"):
        return jsonify({"success": False, "error": "Admin required"}), 403
    data = request.get_json() or {}
    username = (data.get("username") or "").strip()
    password = (data.get("password") or "").strip()
    email = (data.get("email") or "").strip() or None
    clone_from = data.get("clone_from_user_id")
    if not username or not password:
        return jsonify({"success": False, "error": "Username and password required"}), 400
    password_hash = hashlib.sha256(password.encode()).hexdigest()
    with get_connection() as conn:
        cur = db_execute(conn, "SELECT id FROM users WHERE username = ?", (username,))
        if cur.fetchone():
            return jsonify({"success": False, "error": "Username exists"}), 400
        cur = db_execute(conn, "INSERT INTO users (username, password_hash, email) VALUES (?, ?, ?)", (username, password_hash, email))
        new_id = last_insert_id(cur)
        if clone_from and new_id:
            cur2 = db_execute(conn, "SELECT * FROM user_api_keys WHERE user_id = ?", (clone_from,))
            row = cur2.fetchone()
            if row:
                r = dict_row(row)
                r.pop("id"); r.pop("user_id"); r.pop("created_at"); r.pop("updated_at", None)
                cols = ["user_id"] + [k for k in r.keys() if r[k] is not None]
                vals = [new_id] + [r[k] for k in cols if k != "user_id"]
                db_execute(conn, f"INSERT INTO user_api_keys ({','.join(cols)}) VALUES ({','.join(['?']*len(vals))})", vals)
    return jsonify({"success": True})


@app.route("/api/users/clone-profile", methods=["POST"])
@login_required
def api_users_clone_profile():
    if not get_current_user().get("is_admin"):
        return jsonify({"success": False, "error": "Admin required"}), 403
    data = request.get_json() or {}
    src = data.get("source_user_id")
    tgt = data.get("target_user_id")
    if not src or not tgt:
        return jsonify({"success": False, "error": "source_user_id and target_user_id required"}), 400
    with get_connection() as conn:
        cur = db_execute(conn, "SELECT * FROM user_api_keys WHERE user_id = ?", (src,))
        row = cur.fetchone()
        if not row:
            return jsonify({"success": False, "error": "Source has no profile"}), 400
        r = dict_row(row)
        for k in ("id", "user_id", "created_at", "updated_at", "cloned_from_user_id", "cloned_at"):
            r.pop(k, None)
        cols = list(r.keys())
        cur2 = db_execute(conn, "SELECT id FROM user_api_keys WHERE user_id = ?", (tgt,))
        if cur2.fetchone():
            set_clause = ", ".join(f"{k}=?" for k in cols)
            db_execute(conn, f"UPDATE user_api_keys SET {set_clause} WHERE user_id = ?", tuple(r.values()) + (tgt,))
        else:
            db_execute(conn, f"INSERT INTO user_api_keys (user_id, {','.join(cols)}) VALUES (?, {','.join(['?']*len(cols))})", (tgt,) + tuple(r.values()))
    return jsonify({"success": True})


def _seed_all_profiles_ai_prompts_if_missing():
    """Backfill existing profiles with current built-in prompts when ai_prompts_json is empty."""
    defaults = load_builtin_defaults() or {}
    if not defaults:
        return
    seed_json = json.dumps(defaults, ensure_ascii=False)
    with get_connection() as conn:
        cur = db_execute(conn, "SELECT id FROM users")
        user_ids = [dict_row(r).get("id") for r in (cur.fetchall() or []) if dict_row(r).get("id")]
        if not user_ids:
            return
        cur = db_execute(conn, "SELECT user_id, ai_prompts_json FROM user_api_keys")
        rows = [dict_row(r) for r in (cur.fetchall() or [])]
        by_user = {int(r.get("user_id")): (r.get("ai_prompts_json") or "") for r in rows if r.get("user_id") is not None}
        inserted = 0
        updated = 0
        for uid in user_ids:
            existing = str(by_user.get(int(uid)) or "").strip()
            if int(uid) not in by_user:
                db_execute(conn, "INSERT INTO user_api_keys (user_id, ai_prompts_json) VALUES (?, ?)", (uid, seed_json))
                inserted += 1
                continue
            if not existing or existing == "{}":
                db_execute(conn, "UPDATE user_api_keys SET ai_prompts_json = ? WHERE user_id = ?", (seed_json, uid))
                updated += 1
        if inserted or updated:
            log.info("[seed-ai-prompts] inserted=%s updated=%s", inserted, updated)


def _run_startup_seeds():
    """Run DB init and seed HTML templates on app load. Ensures deploy auto-seeds from html_templates.json."""
    try:
        init_db()
        _seed_template_39_if_missing()
        _seed_html_templates_if_missing()
        _seed_all_profiles_ai_prompts_if_missing()
    except Exception as e:
        log.warning("Startup seed: %s", e)


if __name__ == "__main__":
    _run_startup_seeds()
    log.info("Starting Flask on http://0.0.0.0:5001")
    app.run(host="0.0.0.0", port=5001)
else:
    _run_startup_seeds()
